"use client";

import { useState, useEffect } from "react";
import {
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Button,
  TextField,
  Box,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  CircularProgress,
} from "@mui/material";
import { supabase } from "@/lib/supabase";

type Person = {
  id?: string;
  title: string;
  firstName: string;
  lastName: string;
  middleName?: string;
  dob: string;
  isLead: boolean;
  relationship: string;
  addressLine1: string;
  addressLine2?: string;
  city: string;
  county?: string;
  postcode: string;
};

type Props = {
  data: any;
  updateData: (data: any) => void;
  onNext: () => void;
  isSaving: boolean;
};

const CATEGORIES = {
  SINGLE: ["You", "Just for your partner", "Just for one of your parents"],
  DOUBLE: ["You and your partner", "Your mum and dad"],
  UNLIMITED: ["Someone else"],
};

const options = [
  ...CATEGORIES.SINGLE,
  ...CATEGORIES.DOUBLE,
  ...CATEGORIES.UNLIMITED,
];

export default function Step1Who({
  data,
  updateData,
  onNext,
  isSaving,
}: Props) {
  const [loading, setLoading] = useState(true);
  const [selected, setSelected] = useState<string>(data?.selection || "You");
  const [morePeople, setMorePeople] = useState(data?.morePeople || false);
  const [applicationId, setApplicationId] = useState<string | null>(
    data?.applicationId || null,
  );
  const [people, setPeople] = useState<Person[]>(data?.people || []);
  const [selectedPeopleIds, setSelectedPeopleIds] = useState<string[]>(
    data?.selectedPeopleIds || [],
  );
  const [openModal, setOpenModal] = useState(false);
  const [leadPerson, setLeadPerson] = useState<Person | null>(null);

  // New State for View Logic
  const [viewMode, setViewMode] = useState<"CATEGORIES" | "QUANTITY" | "LIST">(
    "CATEGORIES",
  );
  const [selectionLimit, setSelectionLimit] = useState<number>(1);
  const [showManualAddress, setShowManualAddress] = useState(false);

  const [newPerson, setNewPerson] = useState<Omit<Person, "id" | "isLead">>({
    title: "Mr",
    firstName: "",
    lastName: "",
    middleName: "",
    dob: "",
    relationship: "other",
    addressLine1: "",
    addressLine2: "",
    city: "",
    county: "",
    postcode: "",
  });

  useEffect(() => {
    if (isSaving) {
      handleContinue();
    }
  }, [isSaving]);

  const isLeadIncluded =
    selected === "You" || selected === "You and your partner";

  useEffect(() => {
    const init = async () => {
      try {
        const {
          data: { session },
        } = await supabase.auth.getSession();
        if (!session) return;
        const userId = session.user.id;
        const token = session.access_token;

        const leadRes = await fetch(`/api/leads?userId=${userId}`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        const { lead } = await leadRes.json();

        const appsRes = await fetch(`/api/applications?userId=${userId}`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        const { data: apps } = await appsRes.json();
        const currentApp = apps?.find((a: any) => a.status === "draft");

        if (currentApp) {
          setApplicationId(currentApp.id);
          const donorsRes = await fetch(
            `/api/donors?applicationId=${currentApp.id}`,
            { headers: { Authorization: `Bearer ${token}` } },
          );
          const { data: donors } = await donorsRes.json();

          if (donors && donors.length > 0) {
            const mappedPeople = donors.map((d: any) => ({
              id: d.id,
              title: d.title,
              firstName: d.first_name,
              lastName: d.last_name,
              middleName: d.middle_name,
              dob: d.date_of_birth,
              isLead: d.is_lead,
              relationship: d.relationship_to_lead,
              addressLine1: d.address_line_1,
              addressLine2: d.address_line_2,
              city: d.city,
              county: d.county,
              postcode: d.postcode,
            }));

            const dbLeadDonor = mappedPeople.find((p: any) => p.isLead);
            setLeadPerson(
              dbLeadDonor || {
                id: userId,
                title: lead.title,
                firstName: lead.first_name,
                lastName: lead.last_name,
                middleName: lead.middle_name,
                dob: lead.date_of_birth,
                isLead: true,
                relationship: "self",
                addressLine1: lead.address_line_1,
                addressLine2: lead.address_line_2,
                city: lead.city,
                county: lead.county,
                postcode: lead.postcode,
              },
            );

            const others = mappedPeople.filter((p: any) => !p.isLead);
            setPeople(others);

            if (data?.selectedPeopleIds && data.selectedPeopleIds.length > 0) {
              setSelectedPeopleIds(data.selectedPeopleIds);
            } else if (others.length > 0) {
              // On reload, if we have others in DB but no selection in form data,
              // assume all non-lead donors in DB were selected.
              setSelectedPeopleIds(others.map((p: any) => p.id));
            } else {
              setSelectedPeopleIds([]);
            }

            if (donors.length === 1 && donors[0].is_lead) {
              setSelected("You");
              setMorePeople(false);
              setViewMode("CATEGORIES");
            } else {
              setMorePeople(true);
              if (CATEGORIES.SINGLE.includes(data?.selection)) {
                setSelectionLimit(1);
                setViewMode("LIST");
              } else if (CATEGORIES.DOUBLE.includes(data?.selection)) {
                setSelectionLimit(
                  data?.selection === "You and your partner" ? 1 : 2,
                );
                setViewMode("LIST");
              } else if (data?.selection === "Someone else") {
                const count = others.filter((p: any) =>
                  data?.selectedPeopleIds?.includes(p.id),
                ).length;
                setSelectionLimit(count > 1 ? 2 : 1);
                setViewMode("LIST");
              } else {
                setViewMode(data?.selection ? "LIST" : "CATEGORIES");
              }
            }
          } else {
            setLeadPerson({
              id: userId,
              title: lead.title,
              firstName: lead.first_name,
              lastName: lead.last_name,
              middleName: lead.middle_name,
              dob: lead.date_of_birth,
              isLead: true,
              relationship: "self",
              addressLine1: lead.address_line_1,
              addressLine2: lead.address_line_2,
              city: lead.city,
              county: lead.county,
              postcode: lead.postcode,
            });

            if (data?.selection && data.selection !== "You") {
              setMorePeople(true);

              setViewMode("CATEGORIES");
            }
          }
        } else {
          setLeadPerson({
            id: userId,
            title: lead.title,
            firstName: lead.first_name,
            lastName: lead.last_name,
            middleName: lead.middle_name,
            dob: lead.date_of_birth,
            isLead: true,
            relationship: "self",
            addressLine1: lead.address_line_1,
            addressLine2: lead.address_line_2,
            city: lead.city,
            county: lead.county,
            postcode: lead.postcode,
          });
        }
      } catch (err) {
        console.error("Error initialising Who step:", err);
      } finally {
        setLoading(false);
      }
    };
    init();
  }, []);

  useEffect(() => {
    updateData({
      selection: selected,
      people,
      selectedPeopleIds,
      morePeople,
      applicationId,
    });
  }, [selected, people, selectedPeopleIds, morePeople, applicationId]);

  const refinedHandleNextCategory = () => {
    if (selected === "You") {
      setMorePeople(false);
      return;
    }
    setMorePeople(true);

    if (selected === "Someone else") {
      setViewMode("QUANTITY");
    } else if (CATEGORIES.DOUBLE.includes(selected)) {
      if (selected === "You and your partner") {
        setSelectionLimit(1);
      } else {
        setSelectionLimit(2);
      }
      setViewMode("LIST");
      setSelectedPeopleIds([]);
    } else {
      setSelectionLimit(1);
      setViewMode("LIST");
      setSelectedPeopleIds([]);
    }
  };

  const handleQuantitySelection = (limit: number) => {
    setSelectionLimit(limit);
    setViewMode("LIST");
    setSelectedPeopleIds([]);
  };

  const togglePerson = (id: string) => {
    const limit = selectionLimit;

    setSelectedPeopleIds((prev) => {
      if (prev.includes(id)) return prev.filter((pId) => pId !== id);
      if (prev.length < limit) return [...prev, id];
      return prev;
    });
  };

  const handleCreateApplication = async () => {
    const {
      data: { session },
    } = await supabase.auth.getSession();
    if (!session) return null;

    const res = await fetch("/api/applications", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${session.access_token}`,
      },
      body: JSON.stringify({ userId: session.user.id }),
    });
    const { data: app } = await res.json();
    setApplicationId(app.id);
    return app.id;
  };

  const handleAddPerson = async () => {
    if (!newPerson.firstName || !newPerson.lastName) return;

    setLoading(true);
    try {
      const {
        data: { session },
      } = await supabase.auth.getSession();
      if (!session) return;
      const token = session.access_token;

      let appId = applicationId;
      if (!appId) {
        appId = await handleCreateApplication();
      }
      if (!appId) throw new Error("Could not create application");

      const donorBody = {
        application_id: appId,
        is_lead: false,
        title: newPerson.title,
        first_name: newPerson.firstName,
        last_name: newPerson.lastName,
        middle_name: newPerson.middleName,
        date_of_birth: newPerson.dob,
        relationship_to_lead: newPerson.relationship,
        address_line_1: newPerson.addressLine1,
        address_line_2: newPerson.addressLine2,
        city: newPerson.city,
        county: newPerson.county,
        postcode: newPerson.postcode,
      };

      const res = await fetch("/api/donors", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify(donorBody),
      });

      const { data: donor } = await res.json();

      const p: Person = {
        id: donor.id,
        title: donor.title,
        firstName: donor.first_name,
        lastName: donor.last_name,
        middleName: donor.middle_name,
        dob: donor.date_of_birth,
        isLead: false,
        relationship: donor.relationship_to_lead,
        addressLine1: donor.address_line_1,
        addressLine2: donor.address_line_2,
        city: donor.city,
        county: donor.county,
        postcode: donor.postcode,
      };

      setPeople((prev) => [...prev, p]);

      if (selectedPeopleIds.length < selectionLimit) {
        setSelectedPeopleIds((prev) => [...prev, donor.id]);
      }

      setOpenModal(false);
      setShowManualAddress(false);
      setNewPerson({
        title: "Mr",
        firstName: "",
        lastName: "",
        middleName: "",
        dob: "",
        relationship: "other",
        addressLine1: "",
        addressLine2: "",
        city: "",
        county: "",
        postcode: "",
      });
    } catch (err) {
      console.error("Error adding person:", err);
    } finally {
      setLoading(false);
    }
  };

  const handleContinue = async () => {
    setLoading(true);
    try {
      const {
        data: { session },
      } = await supabase.auth.getSession();
      if (!session) return;
      const token = session.access_token;
      const userId = session.user.id;

      let appId = applicationId;
      if (!appId) {
        const createRes = await fetch("/api/applications", {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            Authorization: `Bearer ${token}`,
          },
          body: JSON.stringify({ userId: session.user.id }),
        });
        const { data: app } = await createRes.json();
        appId = app.id;
        setApplicationId(appId);
      }

      const finalSelection: Person[] = [];
      if (isLeadIncluded && leadPerson) finalSelection.push(leadPerson);
      people.forEach((p) => {
        if (selectedPeopleIds.includes(p.id!)) finalSelection.push(p);
      });

      const donorsRes = await fetch(`/api/donors?applicationId=${appId}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      const { data: currentDonors } = await donorsRes.json();

      /*
      const toDelete = currentDonors?.filter((cd: any) => {
        const foundById = finalSelection.some(fs => fs.id === cd.id);
        const isLeadInSelection = finalSelection.some(fs => fs.isLead);
        if (cd.is_lead) return !isLeadInSelection; 
        return !foundById; 
      }) || [];

      for (const p of toDelete) {
        await fetch(`/api/donors?id=${p.id}`, { method: 'DELETE', headers: { Authorization: `Bearer ${token}` } });
      }
      */

      for (const p of finalSelection) {
        const donorBody = {
          application_id: appId,
          is_lead: p.isLead,
          title: p.title,
          first_name: p.firstName,
          last_name: p.lastName,
          middle_name: p.middleName,
          date_of_birth: p.dob,
          relationship_to_lead: p.relationship,
          address_line_1: p.addressLine1,
          address_line_2: p.addressLine2,
          city: p.city,
          county: p.county,
          postcode: p.postcode,
        };

        const existingRecord = p.isLead
          ? currentDonors?.find((cd: any) => cd.is_lead)
          : currentDonors?.find((cd: any) => cd.id === p.id);

        if (existingRecord) {
          await fetch("/api/donors", {
            method: "PATCH",
            headers: {
              "Content-Type": "application/json",
              Authorization: `Bearer ${token}`,
            },
            body: JSON.stringify({ id: existingRecord.id, ...donorBody }),
          });
        } else {
          await fetch("/api/donors", {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
              Authorization: `Bearer ${token}`,
            },
            body: JSON.stringify(donorBody),
          });
        }
      }

      onNext();
    } catch (err) {
      console.error("Error saving step:", err);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <Box display="flex" justifyContent="center" p={4}>
        <CircularProgress color="primary" />
      </Box>
    );
  }

  const renderCategories = () => (
    <div className="space-y-6">
      <p className="text-xl font-medium text-black">
        Who are these documents for?
      </p>
      <div className="grid grid-cols-1 border border-[#adb5bd]">
        {options.map((option) => (
          <button
            key={option}
            onClick={() => setSelected(option)}
            className={`p-5 text-center border-0 transition-all ${
              selected === option
                ? "border-[#08b9ed] bg-[#35495E] text-white font-semibold shadow-sm"
                : "border-gray-100 hover:border-blue-100 text-black"
            }`}
          >
            {option}
          </button>
        ))}
      </div>
      <div className="flex justify-end pt-4">
        <Button
          variant="contained"
          onClick={refinedHandleNextCategory}
          sx={{
            backgroundColor: "#08B9ED",
            textTransform: "none",
            fontWeight: 600,
            "&:hover": { backgroundColor: "#07bdf5ff" },
          }}
        >
          Next
        </Button>
      </div>
    </div>
  );

  const renderQuantitySelection = () => (
    <div className="space-y-6 animate-in fade-in slide-in-from-top-4">
      <div className="flex items-center gap-2 mb-4">
        <button
          onClick={() => setViewMode("CATEGORIES")}
          className="text-sm text-gray-500 hover:text-gray-700 flex items-center gap-1"
        >
          <svg
            className="w-4 h-4"
            fill="none"
            viewBox="0 0 24 24"
            stroke="currentColor"
          >
            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth={2}
              d="M15 19l-7-7 7-7"
            />
          </svg>
          Back
        </button>
      </div>
      <p className="font-semibold text-zenco-dark">
        How many people do you need documents for?
      </p>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <button
          onClick={() => handleQuantitySelection(1)}
          className="p-6 rounded-xl border-2 border-gray-100 hover:border-[#08b9ed] hover:bg-blue-50 transition-all text-center"
        >
          <span className="text-lg font-bold text-zenco-dark block">
            One Person
          </span>
          <span className="text-sm text-gray-500">
            I need documents for 1 person
          </span>
        </button>
        <button
          onClick={() => handleQuantitySelection(2)}
          className="p-6 rounded-xl border-2 border-gray-100 hover:border-[#08b9ed] hover:bg-blue-50 transition-all text-center"
        >
          <span className="text-lg font-bold text-zenco-dark block">
            Two People
          </span>
          <span className="text-sm text-gray-500">
            I need documents for 2 people
          </span>
        </button>
      </div>
    </div>
  );

  const renderList = () => (
    <div className="space-y-6 animate-in fade-in slide-in-from-top-4">
      <p className="text-md text-black">
        You have chosen to make documents for{" "}
        <span className="text-[#08b9ed] font-semibold">{selected}</span>.
      </p>
      <p className="text-sm text-gray-500">
        If you have made a mistake and need these documents for someone else
        then{" "}
        <button
          type="button"
          onClick={() => {
            setViewMode("CATEGORIES");
            setSelectedPeopleIds([]);
          }}
          className="underline text-[#08b9ed] font-medium hover:text-blue-700 px-1"
        >
          click here to change who these documents are for.
        </button>
      </p>

      <div className="">
        {/* Lead Details */}
        {isLeadIncluded && leadPerson && (
          <div className="flex items-center justify-between p-4 rounded-xl border-[#08b9ed] bg-blue-50/50">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-full bg-[#08b9ed]/10 flex items-center justify-center text-[#08b9ed] font-bold">
                {leadPerson.firstName[0]}
              </div>
              <div>
                <p className="font-semibold text-zenco-dark">
                  {leadPerson.firstName} {leadPerson.lastName} (You)
                </p>
                <p className="text-xs text-gray-500">Self</p>
              </div>
            </div>
            <div className="w-6 h-6 rounded-full bg-[#08b9ed] flex items-center justify-center">
              <svg
                className="w-4 h-4 text-white"
                fill="none"
                viewBox="0 0 24 24"
                stroke="currentColor"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={3}
                  d="M5 13l4 4L19 7"
                />
              </svg>
            </div>
          </div>
        )}

        {people.map((person) => {
          const isSelected = selectedPeopleIds.includes(person.id!);
          const limit = selectionLimit;
          const disabled = !isSelected && selectedPeopleIds.length >= limit;

          return (
            <button
              key={person.id}
              disabled={disabled}
              onClick={() => togglePerson(person.id!)}
              className={`w-full flex items-center justify-between p-4 border transition-all ${
                isSelected
                  ? "border-[#08b9ed] bg-white shadow-sm"
                  : disabled
                    ? "border-gray-100 bg-gray-50 opacity-50 cursor-not-allowed"
                    : "border-gray-200 bg-white hover:border-blue-200"
              }`}
            >
              <div className="flex items-center gap-3">
                <div
                  className={`w-10 h-10 rounded-full flex items-center justify-center font-bold ${
                    isSelected
                      ? "bg-[#08b9ed]/10 text-[#08b9ed]"
                      : "bg-gray-100 text-gray-400"
                  }`}
                >
                  {person.firstName[0]}
                </div>
                <div className="text-left">
                  <p
                    className={`font-semibold ${isSelected ? "text-zenco-dark" : "text-black"}`}
                  >
                    {person.firstName} {person.lastName}
                  </p>
                  <p className="text-xs text-gray-400 capitalize">
                    {person.relationship}
                  </p>
                </div>
              </div>
              <div
                className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all ${
                  isSelected
                    ? "bg-[#08b9ed] border-[#08b9ed]"
                    : "border-gray-200 bg-white"
                }`}
              >
                {isSelected && (
                  <svg
                    className="w-3.5 h-3.5 text-white"
                    fill="none"
                    viewBox="0 0 24 24"
                    stroke="currentColor"
                  >
                    <path
                      strokeLinecap="round"
                      strokeLinejoin="round"
                      strokeWidth={3}
                      d="M5 13l4 4L19 7"
                    />
                  </svg>
                )}
              </div>
            </button>
          );
        })}
      </div>

      <Button
        fullWidth
        variant="outlined"
        onClick={() => setOpenModal(true)}
        sx={{
          mt: 2,
          py: 1.5,
          borderColor: "#E5E7EB",
          color: "#374151",
          textTransform: "none",
          fontWeight: 600,
          borderRadius: "0.75rem",
          "&:hover": { borderColor: "#D1D5DB", backgroundColor: "#F9FAFB" },
        }}
      >
        + Add new person
      </Button>

      <div className="flex justify-end pt-4">
        <Button
          variant="contained"
          onClick={handleContinue}
          sx={{
            backgroundColor: "#08B9ED",
            textTransform: "none",
            fontWeight: 600,
            "&:hover": { backgroundColor: "#07bdf5ff" },
          }}
        >
          Continue
        </Button>
      </div>
    </div>
  );

  return (
    <div className="space-y-8">
      <div className="flex flex-col gap-3">
        <h3 className="text-2xl font-semibold text-zenco-dark">
          Who is the{" "}
          <span className="text-[#08b9ed]">Lasting Power of Attorney</span> for?
        </h3>

        {!morePeople ? (
          <div className="space-y-6">
            <p className="text-black">
              You have chosen to make documents for{" "}
              <span className="text-[#08b9ed]">yourself only</span>.
            </p>
            <p className="">
              If you have made a mistake and need these documents for someone
              else then
              <button
                type="button"
                onClick={() => {
                  setMorePeople(true);
                  setViewMode("CATEGORIES");
                }}
                className="underline text-[#08b9ed] font-medium hover:text-blue-700 px-1"
              >
                click here to change who these documents are for.
              </button>
            </p>

            <p>
              Click the continue button to continue making Lasting Power of
              Attorney documents for yourself.
            </p>
            <div className="flex justify-start"></div>
            {/* Continue button for "You" only flow (implied in original layout or handled by WizardLayout) */}
            {/* If we strictly follow the new flow, "You" is just another leaf. But original code had special "You" view. Keeping it. */}
          </div>
        ) : (
          <>
            {viewMode === "CATEGORIES" && renderCategories()}
            {viewMode === "QUANTITY" && renderQuantitySelection()}
            {viewMode === "LIST" && renderList()}
          </>
        )}
      </div>

      <Dialog
        open={openModal}
        onClose={() => setOpenModal(false)}
        fullWidth
        maxWidth="sm"
      >
        <DialogTitle className="font-bold text-zenco-dark">
          Add person
        </DialogTitle>
        <DialogContent className="flex flex-col gap-6 mt-2">
          <p className="font-semibold text-zenco-dark -mb-2">Full legal name</p>
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
            <FormControl fullWidth>
              <InputLabel>Title</InputLabel>
              <Select
                value={newPerson.title}
                label="Title"
                onChange={(e) =>
                  setNewPerson({ ...newPerson, title: e.target.value })
                }
              >
                <MenuItem value="Mr">Mr</MenuItem>
                <MenuItem value="Mrs">Mrs</MenuItem>
                <MenuItem value="Ms">Ms</MenuItem>
                <MenuItem value="Miss">Miss</MenuItem>
                <MenuItem value="Dr">Dr</MenuItem>
                <MenuItem value="Other">Other</MenuItem>
              </Select>
            </FormControl>
            <TextField
              label="First Name"
              fullWidth
              sx={{ md: { gridColumn: "span 1" } }}
              value={newPerson.firstName}
              onChange={(e) =>
                setNewPerson({ ...newPerson, firstName: e.target.value })
              }
            />
            <TextField
              label="Middle names"
              fullWidth
              value={newPerson.middleName}
              onChange={(e) =>
                setNewPerson({ ...newPerson, middleName: e.target.value })
              }
            />
            <TextField
              label="Last Name"
              fullWidth
              value={newPerson.lastName}
              onChange={(e) =>
                setNewPerson({ ...newPerson, lastName: e.target.value })
              }
            />
          </div>

          <p className="font-semibold text-zenco-dark -mb-2">
            What's their date of birth?
          </p>
          <TextField
            type="date"
            fullWidth
            InputLabelProps={{ shrink: true }}
            value={newPerson.dob}
            onChange={(e) =>
              setNewPerson({ ...newPerson, dob: e.target.value })
            }
          />

          <p className="font-semibold text-zenco-dark -mb-2">
            What is their relationship to you?
          </p>
          <FormControl fullWidth>
            <InputLabel>Relationship</InputLabel>
            <Select
              value={newPerson.relationship}
              label="Relationship"
              onChange={(e) =>
                setNewPerson({ ...newPerson, relationship: e.target.value })
              }
            >
              <MenuItem value="partner">Partner</MenuItem>
              <MenuItem value="parent">Parent</MenuItem>
              <MenuItem value="child">Child</MenuItem>
              <MenuItem value="sibling">Sibling</MenuItem>
              <MenuItem value="friend">Friend</MenuItem>
              <MenuItem value="other">Other</MenuItem>
            </Select>
          </FormControl>

          <p className="font-semibold text-zenco-dark -mb-2">
            What is their address?
          </p>
          <div className="grid grid-cols-1 gap-4">
            <div className="flex gap-4 items-end">
              <TextField
                label="Postcode"
                fullWidth
                value={newPerson.postcode}
                onChange={(e) =>
                  setNewPerson({ ...newPerson, postcode: e.target.value })
                }
              />
              <Button
                variant="contained"
                sx={{
                  backgroundColor: "#08B9ED",
                  textTransform: "none",
                  borderRadius: "8px",
                  height: "56px",
                  "&:hover": { backgroundColor: "#07bdf5ff" },
                }}
              >
                Search
              </Button>
            </div>

            {!showManualAddress && (
              <button
                type="button"
                onClick={() => setShowManualAddress(true)}
                className="text-cyan-500 font-semibold text-sm hover:underline text-left w-fit"
              >
                Enter address manually
              </button>
            )}

            {showManualAddress && (
              <div className="space-y-4 animate-in fade-in slide-in-from-top-2">
                <TextField
                  label="Address Line 1"
                  fullWidth
                  value={newPerson.addressLine1}
                  onChange={(e) =>
                    setNewPerson({ ...newPerson, addressLine1: e.target.value })
                  }
                />
                <TextField
                  label="Address Line 2 (Optional)"
                  fullWidth
                  value={newPerson.addressLine2}
                  onChange={(e) =>
                    setNewPerson({ ...newPerson, addressLine2: e.target.value })
                  }
                />
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <TextField
                    label="City"
                    fullWidth
                    value={newPerson.city}
                    onChange={(e) =>
                      setNewPerson({ ...newPerson, city: e.target.value })
                    }
                  />
                  <TextField
                    label="County (Optional)"
                    fullWidth
                    value={newPerson.county}
                    onChange={(e) =>
                      setNewPerson({ ...newPerson, county: e.target.value })
                    }
                  />
                </div>
              </div>
            )}
          </div>
        </DialogContent>
        <DialogActions className="p-4 gap-2">
          <Button
            onClick={() => setOpenModal(false)}
            sx={{ color: "gray", textTransform: "none" }}
          >
            Cancel
          </Button>
          <Button
            variant="contained"
            onClick={handleAddPerson}
            disabled={loading}
            sx={{
              backgroundColor: "#08B9ED",
              textTransform: "none",
              borderRadius: "8px",
              padding: "10px 24px",
              "&:hover": { backgroundColor: "#07bdf5ff" },
            }}
          >
            {loading ? (
              <CircularProgress size={24} color="inherit" />
            ) : (
              "Add Person"
            )}
          </Button>
        </DialogActions>
      </Dialog>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { supabase } from "@/lib/supabase";
import {
  Box,
  FormControl,
  InputLabel,
  MenuItem,
  Select,
  SelectChangeEvent,
  CircularProgress,
  Alert,
} from "@mui/material";
import { log } from "console";

type DocumentSelection =
  | "Health and Welfare"
  | "Property and Finance"
  | "Both"
  | "";

type Props = {
  data: any;
  updateData: (data: any) => void;
  onNext: () => void;
  isSaving: boolean;
  allFormData: any;
};

type Donor = {
  id: string;
  first_name: string;
  last_name: string;
  is_lead: boolean;
  relationship_to_lead: string;
};

export default function Step2WhichDocuments({
  data,
  updateData,
  onNext,
  isSaving,
  allFormData,
}: Props) {
  const [loading, setLoading] = useState(true);
  const [donors, setDonors] = useState<Donor[]>([]);
  const [selections, setSelections] = useState<
    Record<string, DocumentSelection>
  >({});
  const [error, setError] = useState<string | null>(null);

  const applicationId = allFormData?.who?.applicationId;
  const selectedPeopleIds = allFormData?.who?.selectedPeopleIds || [];

  useEffect(() => {
    const init = async () => {
      if (!applicationId) {
        setLoading(false);
        return;
      }

      try {
        const {
          data: { session },
        } = await supabase.auth.getSession();
        if (!session) return;
        const token = session.access_token;

        const donorsRes = await fetch(
          `/api/donors?applicationId=${applicationId}`,
          {
            headers: { Authorization: `Bearer ${token}` },
          },
        );
        const { data: fetchedDonors } = await donorsRes.json();

        if (!fetchedDonors) {
          setDonors([]);
          setLoading(false);
          return;
        }

        const step1Selection = allFormData?.who?.selection;
        const step1SelectedIds = allFormData?.who?.selectedPeopleIds || [];

        const isLeadSelected =
          step1Selection === "You" ||
          step1Selection === "You and your partner" ||
          step1Selection === "You and someone else";

        const activeDonors = fetchedDonors.filter((d: any) => {
          if (d.is_lead) return isLeadSelected;
          return step1SelectedIds.includes(d.id);
        });

        setDonors(activeDonors);

        const initialSelections: Record<string, DocumentSelection> = {};

        await Promise.all(
          activeDonors.map(async (donor: Donor) => {
            const lpasRes = await fetch(
              `/api/lpa-documents?donorId=${donor.id}`,
              {
                headers: { Authorization: `Bearer ${token}` },
              },
            );
            const { data: lpas } = await lpasRes.json();

            if (lpas && Array.isArray(lpas)) {
              const hasHealth = lpas.some(
                (doc: any) => doc.lpa_type === "health_and_welfare",
              );
              const hasFinance = lpas.some(
                (doc: any) => doc.lpa_type === "property_and_finance",
              );

              if (hasHealth && hasFinance) initialSelections[donor.id] = "Both";
              else if (hasHealth)
                initialSelections[donor.id] = "Health and Welfare";
              else if (hasFinance)
                initialSelections[donor.id] = "Property and Finance";
              else initialSelections[donor.id] = "";
            } else {
              initialSelections[donor.id] = "";
            }
          }),
        );

        setSelections(initialSelections);
      } catch (err) {
        console.error("Error loading Step 2:", err);
        setError("Failed to load donor data.");
      } finally {
        setLoading(false);
      }
    };

    init();
  }, [applicationId, allFormData?.who]);

  useEffect(() => {
    if (isSaving) {
      handleSave();
    }
  }, [isSaving]);

  const handleSelectionChange = (donorId: string, value: DocumentSelection) => {
    setSelections((prev) => ({ ...prev, [donorId]: value }));
  };

  const handleSave = async () => {
    try {
      
      const {
        data: { session },
      } = await supabase.auth.getSession();
      if (!session) return;
      const token = session.access_token;

      for (const donor of donors) {
        const selection = selections[donor.id];
        if (!selection) continue;
        const lpasRes = await fetch(`/api/lpa-documents?donorId=${donor.id}`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        const { data: currentLpas } = await lpasRes.json();
        const currentDocs = Array.isArray(currentLpas) ? currentLpas : [];

        const needsHealth =
          selection === "Health and Welfare" || selection === "Both";
        const needsFinance =
          selection === "Property and Finance" || selection === "Both";

        const existingHealth = currentDocs.find(
          (d: any) => d.lpa_type === "health_and_welfare",
        );
        const existingFinance = currentDocs.find(
          (d: any) => d.lpa_type === "property_and_finance",
        );

        if (needsHealth && !existingHealth) {
          console.log("Creating Health & Welfare document for", donor.id);
          const res = await fetch("/api/lpa-documents", {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
              Authorization: `Bearer ${token}`,
            },
            body: JSON.stringify({
              donor_id: donor.id,
              lpa_type: "health_and_welfare",
              status: "draft",
            }),
          });
          const result = await res.json();
          if (result.error) {
            console.error("Failed to create Health document:", result.error);
            setError(
              `Failed to create Health document for ${donor.first_name}`,
            );
            return;
          }
        } else if (!needsHealth && existingHealth) {
          console.log(
            "Soft-deleting Health & Welfare document",
            existingHealth.id,
          );
          const res = await fetch(`/api/lpa-documents`, {
            method: "PATCH",
            headers: {
              "Content-Type": "application/json",
              Authorization: `Bearer ${token}`,
            },
            body: JSON.stringify({
              id: existingHealth.id,
              deleted_at: new Date().toISOString(),
            }),
          });
          const result = await res.json();
          if (result.error)
            console.error("Failed to delete Health document:", result.error);
        } else if (needsHealth && existingHealth && existingHealth.deleted_at) {
          console.log(
            "Reactivating Health & Welfare document",
            existingHealth.id,
          );
          await fetch("/api/lpa-documents", {
            method: "PATCH",
            headers: {
              "Content-Type": "application/json",
              Authorization: `Bearer ${token}`,
            },
            body: JSON.stringify({ id: existingHealth.id, deleted_at: null }),
          });
        }

        if (needsFinance && !existingFinance) {
          console.log("Creating Property & Finance document for", donor.id);
          const res = await fetch("/api/lpa-documents", {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
              Authorization: `Bearer ${token}`,
            },
            body: JSON.stringify({
              donor_id: donor.id,
              lpa_type: "property_and_finance",
              status: "draft",
            }),
          });
          const result = await res.json();
          if (result.error) {
            console.error("Failed to create Finance document:", result.error);
            setError(
              `Failed to create Finance document for ${donor.first_name}`,
            );
            return;
          }
        } else if (!needsFinance && existingFinance) {
          console.log(
            "Soft-deleting Property & Finance document",
            existingFinance.id,
          );
          const res = await fetch(`/api/lpa-documents`, {
            method: "PATCH",
            headers: {
              "Content-Type": "application/json",
              Authorization: `Bearer ${token}`,
            },
            body: JSON.stringify({
              id: existingFinance.id,
              deleted_at: new Date().toISOString(),
            }),
          });
          const result = await res.json();
          if (result.error)
            console.error("Failed to delete Finance document:", result.error);
        } else if (
          needsFinance &&
          existingFinance &&
          existingFinance.deleted_at
        ) {
          console.log(
            "Reactivating Property & Finance document",
            existingFinance.id,
          );
          await fetch("/api/lpa-documents", {
            method: "PATCH",
            headers: {
              "Content-Type": "application/json",
              Authorization: `Bearer ${token}`,
            },
            body: JSON.stringify({ id: existingFinance.id, deleted_at: null }),
          });
        }
      }

      updateData({ selections });
      onNext();
    } catch (err) {
      console.error("Error saving documents:", err);
      setError("Failed to save document selections.");
    }
  };

  if (loading) {
    return (
      <Box display="flex" justifyContent="center" p={4}>
        <CircularProgress />
      </Box>
    );
  }

  if (error) {
    return <Alert severity="error">{error}</Alert>;
  }

  return (
    <section className="space-y-8 animate-in fade-in slide-in-from-top-4">
      <div className="flex flex-col gap-5">
        <h1 className="text-2xl font-bold text-black">
          Which{" "}
          <span className="text-[#08b9ed]">Lasting Power of Attorney</span>{" "}
          documents do you need?
        </h1>
        <p className="text-black">
          You need to choose which type of documents you want. Choose Health and
          Welfare for health decisions, Property and Finance for decisions about
          your finances, or choose Both.
        </p>
        <div className="flex items-end gap-3 font-semibold">
          <span className="">
            <svg
              xmlns="http://www.w3.org/2000/svg"
              viewBox="0 0 640 640"
              width="24"
              height="24"
              fill="currentColor"
              className="text-[#08b9ed]"
            >
              <path d="M420.9 448C428.2 425.7 442.8 405.5 459.3 388.1C492 353.7 512 307.2 512 256C512 150 426 64 320 64C214 64 128 150 128 256C128 307.2 148 353.7 180.7 388.1C197.2 405.5 211.9 425.7 219.1 448L420.8 448zM416 496L224 496L224 512C224 556.2 259.8 592 304 592L336 592C380.2 592 416 556.2 416 512L416 496zM312 176C272.2 176 240 208.2 240 248C240 261.3 229.3 272 216 272C202.7 272 192 261.3 192 248C192 181.7 245.7 128 312 128C325.3 128 336 138.7 336 152C336 165.3 325.3 176 312 176z" />
            </svg>
          </span>
          <p className="text-sm text-black">
            We strongly recommend taking both documents for peace of mind and
            the best protection.
          </p>
        </div>
      </div>

      <div className="flex flex-col gap-6">
        {donors.map((donor) => (
          <div
            key={donor.id}
            className=""
          >
            <h3 className="text-xl font-medium text-black mb-4">
              Which documents does{" "}
              <span className="text-[#08b9ed]">
                {donor.first_name} {donor.last_name}
              </span>{" "}
             need?
            </h3>
            <FormControl fullWidth>
              <p>Document Selection</p>
              <Select
                value={selections[donor.id] || ""}
                // label="Document Selection"
                onChange={(e) =>
                  handleSelectionChange(
                    donor.id,
                    e.target.value as DocumentSelection,
                  )
                }
              >
                <MenuItem value="Health and Welfare">
                  Health and Welfare
                </MenuItem>
                <MenuItem value="Property and Finance">
                  Property and Finance
                </MenuItem>
                <MenuItem value="Both">Both</MenuItem>
              </Select>
            </FormControl>
          </div>
        ))}

        {donors.length === 0 && (
          <Alert severity="info">
            No people selected. Please go back and select who this LPA is for.
          </Alert>
        )}
      </div>
    </section>
  );
}

"use client";

import {
  Button,
  FormControl,
  InputLabel,
  MenuItem,
  Select,
  TextField,
  CircularProgress,
  Alert,
  Box
} from "@mui/material";
import { useState, useEffect } from "react";
import { supabase } from "@/lib/supabase";
import styles from "./Steps.module.css";

type Props = {
  data: any;
  updateData: (data: any) => void;
  onNext: () => void;
  isSaving: boolean;
  allFormData: any;
  currentDonorIndex: number;
};

export default function DonorTab({ onNext, isSaving, allFormData, updateData, currentDonorIndex }: Props) {
  const [loading, setLoading] = useState(true);
  const [showManualAddress, setShowManualAddress] = useState(false);
  const [currentDonor, setCurrentDonor] = useState<any>(null);
  const [error, setError] = useState<string | null>(null);

  const [subStep, setSubStep] = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [formData, setFormData] = useState({
    title: "",
    firstName: "",
    lastName: "",
    middleName: "",
    preferredName: "",
    day: "",
    month: "",
    year: "",
    postcode: "",
    address: "",
    mobile: "",
    landline: "",
    city: "",
    county: "",
    addressLine2: ""
  });

  const applicationId = allFormData?.who?.applicationId;

  useEffect(() => {
    const init = async () => {
      if (!applicationId) {
        setLoading(false);
        return;
      }

      try {
        const { data: { session } } = await supabase.auth.getSession();
        if (!session) return;
        const token = session.access_token;

        const donorsRes = await fetch(`/api/donors?applicationId=${applicationId}`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        const { data: fetchedDonors } = await donorsRes.json();

        if (!fetchedDonors) {
          setLoading(false);
          return;
        }

        const step1Selection = allFormData?.who?.selection;
        const step1SelectedIds = allFormData?.who?.selectedPeopleIds || [];
        const isLeadSelected =
          step1Selection === "You" ||
          step1Selection === "You and your partner" ||
          step1Selection === "You and someone else";

        const activeDonors = (fetchedDonors || []).filter((d: any) => {
          if (d.is_lead) return isLeadSelected;
          return step1SelectedIds.includes(d.id);
        });

        const firstDonor = activeDonors[currentDonorIndex];

        if (firstDonor) {
          setCurrentDonor(firstDonor);

          let day = "", month = "", year = "";
          if (firstDonor.date_of_birth) {
            const date = new Date(firstDonor.date_of_birth);
            day = String(date.getDate());

            const months = [
              "January", "February", "March", "April", "May", "June",
              "July", "August", "September", "October", "November", "December"
            ];
            month = months[date.getMonth()];
            year = String(date.getFullYear());
          }

          setFormData({
            title: firstDonor.title || "",
            firstName: firstDonor.first_name || "",
            lastName: firstDonor.last_name || "",
            middleName: firstDonor.middle_name || "",
            preferredName: firstDonor.preferred_name || "",
            day,
            month,
            year,
            postcode: firstDonor.postcode || "",
            address: firstDonor.address_line_1 || "",
            addressLine2: firstDonor.address_line_2 || "",
            city: firstDonor.city || "",
            county: firstDonor.county || "",
            mobile: "",
            landline: ""
          });
        }

      } catch (err) {
        console.error("Error loading Step 3:", err);
        setError("Failed to load donor details.");
      } finally {
        setLoading(false);
      }
    };

    init();
  }, [applicationId, allFormData?.who, currentDonorIndex]);

  const handleInternalNext = async () => {
    if (subStep === 0) {

      setSubStep(1);
      window.scrollTo(0, 0);
    } else {
      setIsSubmitting(true);
      await handleSave();
      setIsSubmitting(false);
    }
  };

  const handleInternalBack = () => {
    if (subStep === 1) {
      setSubStep(0);
      window.scrollTo(0, 0);
    }
  };

  const handleSave = async () => {
    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) return;
      const token = session.access_token;

      const monthIdx = [
        "January", "February", "March", "April", "May", "June",
        "July", "August", "September", "October", "November", "December"
      ].indexOf(formData.month);

      let dob = null;
      if (formData.year && formData.month && formData.day) {

        const m = String(monthIdx + 1).padStart(2, '0');
        const d = String(formData.day).padStart(2, '0');
        dob = `${formData.year}-${m}-${d}`;
      }

      const body = {
        id: currentDonor.id,
        title: formData.title,
        first_name: formData.firstName,
        last_name: formData.lastName,
        middle_name: formData.middleName,
        preferred_name: formData.preferredName,
        date_of_birth: dob,
        address_line_1: formData.address,
        address_line_2: formData.addressLine2,
        city: formData.city,
        county: formData.county,
        postcode: formData.postcode,

      };

      await fetch("/api/donors", {
        method: "PATCH",
        headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` },
        body: JSON.stringify(body)
      });

      updateData({ donorId: currentDonor.id });

      onNext();
    } catch (err) {
      console.error("Error saving donor:", err);
      setError("Failed to save details.");
    }
  };

  const handleFormChange = (field: string, value: string) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
  };

  if (loading) return <Box p={4} display="flex" justifyContent="center"><CircularProgress /></Box>;
  if (error) return <Alert severity="error">{error}</Alert>;
  if (!currentDonor) return <Alert severity="info">No donor found. Please go back.</Alert>;

  const donorName = `${currentDonor.first_name} ${currentDonor.last_name}`;

  return (
    <section className="space-y-8  p-2 animate-in fade-in slide-in-from-top-4">
      <div className="flex flex-col gap-5">
        <h1 className={`text-center text-3xl ${styles.headingBorderBottom} font-bold text-zenco-dark`}>
          Details for <span className="text-zenco-blue">{donorName}</span> (The Donor)
        </h1>
 
        {subStep === 0 && (
          <div className="flex flex-col gap-3 text-gray-600">
            <p>The 'Donor' is the person appointing other people to make decisions on their behalf and must be:</p>
            <ul className="list-none space-y-2">
              <li className="flex items-center gap-2">
                <svg className="w-5 h-5 text-green-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
                Aged 18 or over.
              </li>
              <li className="flex items-center gap-2">
                <svg className="w-5 h-5 text-green-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
                Have mental capacity to make decisions at the time their Lasting Power of Attorney is being made.
              </li>
            </ul>
            <p>The Donor is the only one who can make decisions about their Lasting Power of Attorney and the people it should involve.</p>
          </div>
        )}
      </div>

      <div className="space-y-8">

        {/* SUB-STEP 0: PERSONAL DETAILS */}
        {subStep === 0 && (
          <div className="space-y-8 animate-in fade-in">
            <h3 className="font-semibold text-lg text-zenco-dark border-b pb-2">Full legal name</h3>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <FormControl fullWidth>
                <InputLabel>Title</InputLabel>
                <Select value={formData.title} label="Title" onChange={(e) => handleFormChange("title", e.target.value)}>
                  {["Mr", "Mrs", "Miss", "Ms", "Mx", "Dr", "Rev", "Prof", "Lady", "Lord"].map((t) => (
                    <MenuItem key={t} value={t}>{t}</MenuItem>
                  ))}
                </Select>
              </FormControl>
              <TextField label="First Name" value={formData.firstName} onChange={(e) => handleFormChange("firstName", e.target.value)} fullWidth />
              <TextField label="Last Name" value={formData.lastName} onChange={(e) => handleFormChange("lastName", e.target.value)} fullWidth />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <TextField label="Middle names (if any)" value={formData.middleName} onChange={(e) => handleFormChange("middleName", e.target.value)} fullWidth />
              <TextField label="Preferred Name (Optional)" value={formData.preferredName} onChange={(e) => handleFormChange("preferredName", e.target.value)} fullWidth />
            </div>

            <h3 className="font-semibold text-lg text-zenco-dark border-b pb-2 mt-8">Date of birth</h3>
            <div className="grid grid-cols-3 gap-6">
              <FormControl fullWidth>
                <InputLabel>Day</InputLabel>
                <Select value={formData.day} label="Day" onChange={(e) => handleFormChange("day", e.target.value)}>
                  {[...Array(31)].map((_, i) => <MenuItem key={i + 1} value={String(i + 1)}>{i + 1}</MenuItem>)}
                </Select>
              </FormControl>
              <FormControl fullWidth>
                <InputLabel>Month</InputLabel>
                <Select value={formData.month} label="Month" onChange={(e) => handleFormChange("month", e.target.value)}>
                  {["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"].map((m) => (
                    <MenuItem key={m} value={m}>{m}</MenuItem>
                  ))}
                </Select>
              </FormControl>
              <FormControl fullWidth>
                <InputLabel>Year</InputLabel>
                <Select value={formData.year} label="Year" onChange={(e) => handleFormChange("year", e.target.value)}>
                  {Array.from({ length: 110 }, (_, i) => {
                    const y = new Date().getFullYear() - i;
                    return <MenuItem key={y} value={String(y)}>{y}</MenuItem>
                  })}
                </Select>
              </FormControl>
            </div>
          </div>
        )}

        {/* SUB-STEP 1: ADDRESS & CONTACT DETAILS */}
        {subStep === 1 && (
          <div className="space-y-8 animate-in fade-in">
            <h3 className="font-semibold text-lg text-zenco-dark border-b pb-2">Address & Contact</h3>
            <div className="space-y-4">
              <div className="flex gap-4 items-end">
                <TextField
                  label="Postcode"
                  value={formData.postcode || ""}
                  onChange={(e) => handleFormChange("postcode", e.target.value)}
                  fullWidth
                />
                <Button
                  variant="contained"
                  sx={{
                    backgroundColor: "#08B9ED",
                    color: "white",
                    padding: "10px 24px",
                    height: "56px",
                    textTransform: "none",
                    fontWeight: 600,
                    "&:hover": { backgroundColor: "#07bdf5ff" }
                  }}
                >
                  Search
                </Button>
              </div>

              {!showManualAddress && (
                <button
                  type="button"
                  onClick={() => setShowManualAddress(true)}
                  className="text-cyan-500 font-semibold text-sm hover:underline text-left w-fit"
                >
                  Enter address manually
                </button>
              )}

              {showManualAddress && (
                <div className="flex flex-col gap-4 md:gap-6 animate-in fade-in slide-in-from-top-2">
                  <TextField
                    label="Address Line 1"
                    value={formData.address || ""}
                    onChange={(e) => handleFormChange("address", e.target.value)}
                    fullWidth
                  />
                  <TextField
                    label="Address Line 2 (Optional)"
                    value={formData.addressLine2 || ""}
                    onChange={(e) => handleFormChange("addressLine2", e.target.value)}
                    fullWidth
                  />
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-6">
                    <TextField
                      label="City"
                      value={formData.city || ""}
                      onChange={(e) => handleFormChange("city", e.target.value)}
                      fullWidth
                    />
                    <TextField
                      label="County (Optional)"
                      value={formData.county || ""}
                      onChange={(e) => handleFormChange("county", e.target.value)}
                      fullWidth
                    />
                  </div>
                </div>
              )}
            </div>
          </div>
        )}
      </div>

      {/* Internal Navigation Buttons */}
      <div className="flex justify-between pt-6">
        <Button
          onClick={handleInternalBack}
          sx={{ color: '#6b7280', textTransform: 'none', opacity: subStep === 0 ? 0 : 1 }}
          disabled={subStep === 0}
        >
          Back
        </Button>

        <Button
          variant="contained"
          onClick={handleInternalNext}
          disabled={isSubmitting}
          sx={{
            backgroundColor: "#08B9ED", // zenco-blue
            textTransform: "none",
            borderRadius: "8px",
            padding: "8px 32px",
            "&:hover": { backgroundColor: "#1d4ed8" },
          }}
        >
          {subStep === 1 ? (isSubmitting ? <CircularProgress size={24} color="inherit" /> : "Save and Continue") : "Save and Continue"}
        </Button>
      </div>
    </section>
  );
}

"use client";

import { useState, useEffect } from "react";
import {
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Button,
  TextField,
  Box,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  CircularProgress,
  Alert,
} from "@mui/material";
import { supabase } from "@/lib/supabase";
import styles from "./Steps.module.css";

type Person = {
  id: string;
  title: string;
  first_name: string;
  last_name: string;
  middle_name?: string;
  date_of_birth?: string;
  is_lead: boolean;
  address_line_1?: string;
  address_line_2?: string;
  city?: string;
  county?: string;
  postcode?: string;
  email?: string;
};

type Props = {
  data: any;
  updateData: (data: any) => void;
  onNext: () => void;
  isSaving: boolean;
  allFormData: any;
  currentDonorIndex: number;
};

const emptyForm = {
  title: "Mr",
  firstName: "",
  lastName: "",
  middleName: "",
  dob: "",
  addressLine1: "",
  addressLine2: "",
  city: "",
  county: "",
  postcode: "",
  email: "",
};

export default function AttorneysTab({ onNext, isSaving, allFormData, updateData, currentDonorIndex }: Props) {
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [subStep, setSubStep] = useState(0);

  const [peoplePool, setPeoplePool] = useState<Person[]>([]);

  const [selectedAttorneyIds, setSelectedAttorneyIds] = useState<string[]>([]);
  const [showManualAddress, setShowManualAddress] = useState(false);

  const [canViewDocuments, setCanViewDocuments] = useState<boolean | null>(null);

  const [wantsReplacement, setWantsReplacement] = useState<boolean | null>(null);
  const [selectedReplacementIds, setSelectedReplacementIds] = useState<string[]>([]);

  const [openModal, setOpenModal] = useState(false);
  const [modalMode, setModalMode] = useState<"attorney" | "replacement">("attorney");
  const [editingPersonId, setEditingPersonId] = useState<string | null>(null); // null = add new, string = editing existing
  const [formData, setFormData] = useState({ ...emptyForm });

  const applicationId = allFormData?.who?.applicationId;

  useEffect(() => {
    const init = async () => {
      if (!applicationId) { setLoading(false); return; }
      try {
        const { data: { session } } = await supabase.auth.getSession();
        if (!session) return;
        const token = session.access_token;

        const donorsRes = await fetch(`/api/donors?applicationId=${applicationId}`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        const { data: donors } = await donorsRes.json();

        if (donors && donors.length > 0) {
          const step1Selection = allFormData?.who?.selection;
          const step1SelectedIds = allFormData?.who?.selectedPeopleIds || [];
          const isLeadSelected =
            step1Selection === "You" ||
            step1Selection === "You and your partner" ||
            step1Selection === "You and someone else";

          const activeDonors = donors.filter((d: any) => {
            if (d.is_lead) return isLeadSelected;
            return step1SelectedIds.includes(d.id);
          });
          const subjectDonorId = activeDonors[currentDonorIndex]?.id;

          const pool = donors.filter((d: any) => d.id !== subjectDonorId);
          setPeoplePool(pool);
        }

        const attorneysRes = await fetch(`/api/attorneys?applicationId=${applicationId}`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        const { data: existingAttorneys } = await attorneysRes.json();

        if (existingAttorneys && existingAttorneys.length > 0) {
          setPeoplePool((prev) => {
            // Filter out any duplicates if they were already in the pool from the donor check
            const newAttorneys = existingAttorneys.filter((ea: any) => !prev.some(p => p.id === ea.id));
            return [...prev, ...newAttorneys];
          });
        }

        const savedData = allFormData?.attorneys;
        if (savedData) {
          if (savedData.selectedAttorneyIds) setSelectedAttorneyIds(savedData.selectedAttorneyIds);
          if (savedData.selectedReplacementIds) setSelectedReplacementIds(savedData.selectedReplacementIds);
          if (savedData.canViewDocuments !== undefined) setCanViewDocuments(savedData.canViewDocuments);
          if (savedData.wantsReplacement !== undefined) setWantsReplacement(savedData.wantsReplacement);
        }
      } catch (err) {
        console.error("Error loading Step 4:", err);
        setError("Failed to load attorney details.");
      } finally {
        setLoading(false);
      }
    };
    init();
  }, [applicationId, currentDonorIndex, allFormData?.who]);


  const toggleAttorney = (id: string) => {
    setSelectedAttorneyIds((prev) =>
      prev.includes(id) ? prev.filter((x) => x !== id) : [...prev, id]
    );
  };

  const toggleReplacement = (id: string) => {
    setSelectedReplacementIds((prev) =>
      prev.includes(id) ? prev.filter((x) => x !== id) : [...prev, id]
    );
  };

  const openAddModal = (mode: "attorney" | "replacement") => {
    setModalMode(mode);
    setEditingPersonId(null);
    setFormData({ ...emptyForm });
    setOpenModal(true);
  };

  const openEditModal = (person: Person, mode: "attorney" | "replacement") => {
    setModalMode(mode);
    setEditingPersonId(person.id);
    setFormData({
      title: person.title || "Mr",
      firstName: person.first_name || "",
      lastName: person.last_name || "",
      middleName: person.middle_name || "",
      dob: person.date_of_birth || "",
      addressLine1: person.address_line_1 || "",
      addressLine2: person.address_line_2 || "",
      city: person.city || "",
      county: person.county || "",
      postcode: person.postcode || "",
      email: person.email || "",
    });
    setOpenModal(true);
  };

  const handleSaveModal = async () => {
    if (!formData.firstName || !formData.lastName) return;
    setIsSubmitting(true);
    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) return;
      const token = session.access_token;

      const attorneyBody: any = {
        application_id: applicationId,
        title: formData.title,
        first_name: formData.firstName,
        last_name: formData.lastName,
        middle_name: formData.middleName,
        date_of_birth: formData.dob || null,
        address_line_1: formData.addressLine1,
        address_line_2: formData.addressLine2,
        city: formData.city,
        county: formData.county,
        postcode: formData.postcode,
        email: formData.email,
      };

      if (editingPersonId) {
        const res = await fetch("/api/attorneys", {
          method: "PATCH",
          headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` },
          body: JSON.stringify({ id: editingPersonId, ...attorneyBody }),
        });
        const { data: updated } = await res.json();

        if (updated) {
          setPeoplePool((prev) =>
            prev.map((p) => (p.id === editingPersonId ? updated : p))
          );
        }
      } else {
        const res = await fetch("/api/attorneys", {
          method: "POST",
          headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` },
          body: JSON.stringify(attorneyBody),
        });
        const { data: attorney } = await res.json();

        if (attorney) {
          setPeoplePool((prev) => [...prev, attorney]);
          if (modalMode === "attorney") {
            setSelectedAttorneyIds((prev) => [...prev, attorney.id]);
          } else {
            setSelectedReplacementIds((prev) => [...prev, attorney.id]);
          }
        }
      }

      setOpenModal(false);
      setFormData({ ...emptyForm });
      setEditingPersonId(null);
    } catch (err) {
      console.error("Error saving person:", err);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleInternalNext = async () => {
    if (subStep === 0) {
      if (selectedAttorneyIds.length === 0) {
        setError("Please select at least one attorney.");
        return;
      }
      setError(null);
      setSubStep(1);
      window.scrollTo(0, 0);
    } else if (subStep === 1) {
      if (canViewDocuments === null) {
        setError("Please select an option.");
        return;
      }
      setError(null);
      setSubStep(2);
      window.scrollTo(0, 0);
    } else {
      setIsSubmitting(true);
      try {
        const { data: { session } } = await supabase.auth.getSession();
        if (!session) return;
        const token = session.access_token;

        let activeDonorId = allFormData?.["which-donor"]?.donorId;

        if (!activeDonorId) {
          const donorsRes = await fetch(`/api/donors?applicationId=${applicationId}`, {
            headers: { Authorization: `Bearer ${token}` },
          });
          const { data: allDonors } = await donorsRes.json();
          if (allDonors && allDonors.length > 0) {
            const step1Selection = allFormData?.who?.selection;
            const step1SelectedIds = allFormData?.who?.selectedPeopleIds || [];
            const isLeadSelected =
              step1Selection === "You" ||
              step1Selection === "You and your partner" ||
              step1Selection === "You and someone else";
            const activeDonors = allDonors.filter((d: any) => {
              if (d.is_lead) return isLeadSelected;
              return step1SelectedIds.includes(d.id);
            });
            activeDonorId = activeDonors[0]?.id;
          }
        }

        if (!activeDonorId) {
          setError("Could not find the donor. Please go back to Step 3.");
          setIsSubmitting(false);
          return;
        }

        const lpaDocsRes = await fetch(`/api/lpa-documents?donorId=${activeDonorId}`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        const { data: lpaDocs } = await lpaDocsRes.json();

        if (lpaDocs && lpaDocs.length > 0) {
          for (const doc of lpaDocs) {
            const junctionRes = await fetch(`/api/lpa-document-attorneys?lpaDocId=${doc.id}`, {
              headers: { Authorization: `Bearer ${token}` },
            });
            const { data: existingLinks } = await junctionRes.json();
            if (existingLinks && existingLinks.length > 0) {
              for (const link of existingLinks) {
                await fetch(`/api/lpa-document-attorneys?id=${link.id}`, {
                  method: "DELETE",
                  headers: { Authorization: `Bearer ${token}` },
                });
              }
            }

            await fetch(`/api/lpa-document-applicants?lpaDocId=${doc.id}`, {
              method: "DELETE",
              headers: { Authorization: `Bearer ${token}` },
            });
          }
        }

        const existingAttRes = await fetch(`/api/attorneys?applicationId=${applicationId}`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        const { data: existingAttorneys } = await existingAttRes.json();
        if (existingAttorneys && existingAttorneys.length > 0) {
          for (const att of existingAttorneys) {
            await fetch(`/api/attorneys?id=${att.id}`, {
              method: "DELETE",
              headers: { Authorization: `Bearer ${token}` },
            });
          }
        }

        const primaryAttorneyDbIds: string[] = [];
        for (const donorId of selectedAttorneyIds) {
          const person = peoplePool.find((p) => p.id === donorId);
          if (!person) continue;

          const res = await fetch("/api/attorneys", {
            method: "POST",
            headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` },
            body: JSON.stringify({
              application_id: applicationId,
              title: person.title,
              first_name: person.first_name,
              last_name: person.last_name,
              middle_name: person.middle_name,
              date_of_birth: person.date_of_birth,
              address_line_1: person.address_line_1,
              address_line_2: person.address_line_2,
              city: person.city,
              county: person.county,
              postcode: person.postcode,
              email: person.email,
            }),
          });
          const { data: attorney } = await res.json();
          if (attorney) primaryAttorneyDbIds.push(attorney.id);
        }

        const replacementAttorneyDbIds: string[] = [];
        if (wantsReplacement) {
          for (const donorId of selectedReplacementIds) {
            const person = peoplePool.find((p) => p.id === donorId);
            if (!person) continue;

            const res = await fetch("/api/attorneys", {
              method: "POST",
              headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` },
              body: JSON.stringify({
                application_id: applicationId,
                title: person.title,
                first_name: person.first_name,
                last_name: person.last_name,
                middle_name: person.middle_name,
                date_of_birth: person.date_of_birth,
                address_line_1: person.address_line_1,
                address_line_2: person.address_line_2,
                city: person.city,
                county: person.county,
                postcode: person.postcode,
                email: person.email,
              }),
            });
            const { data: attorney } = await res.json();
            if (attorney) replacementAttorneyDbIds.push(attorney.id);
          }
        }

        if (lpaDocs && lpaDocs.length > 0) {
          for (const doc of lpaDocs) {
            for (let i = 0; i < primaryAttorneyDbIds.length; i++) {
              await fetch("/api/lpa-document-attorneys", {
                method: "POST",
                headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` },
                body: JSON.stringify({
                  lpa_document_id: doc.id,
                  attorney_id: primaryAttorneyDbIds[i],
                  role: "primary",
                  sort_order: i + 1,
                }),
              });
            }

            for (let i = 0; i < replacementAttorneyDbIds.length; i++) {
              await fetch("/api/lpa-document-attorneys", {
                method: "POST",
                headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` },
                body: JSON.stringify({
                  lpa_document_id: doc.id,
                  attorney_id: replacementAttorneyDbIds[i],
                  role: "replacement",
                  sort_order: i + 1,
                }),
              });
            }

            await fetch("/api/lpa-document-applicants", {
              method: "POST",
              headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` },
              body: JSON.stringify({
                lpa_document_id: doc.id,
                applicant_role: "donor",
                attorney_id: null,
              }),
            });
          }
        }

        const attorneyObjects = selectedAttorneyIds.map(id => {
          const p = peoplePool.find(pp => pp.id === id);
          return p ? { firstName: p.first_name, lastName: p.last_name, address: p.postcode, dob: p.date_of_birth } : null;
        }).filter(Boolean);

        const replacementObjects = selectedReplacementIds.map(id => {
          const p = peoplePool.find(pp => pp.id === id);
          return p ? { firstName: p.first_name, lastName: p.last_name, address: p.postcode, dob: p.date_of_birth } : null;
        }).filter(Boolean);

        updateData({
          selectedAttorneyIds,
          selectedReplacementIds,
          canViewDocuments,
          wantsReplacement,
          attorneys: attorneyObjects,
          replacementAttorneys: replacementObjects
        });

        onNext();
      } catch (err) {
        console.error("Error saving attorneys:", err);
        setError("Failed to save attorney details.");
      } finally {
        setIsSubmitting(false);
      }
    }
  };

  const handleInternalBack = () => {
    if (subStep > 0) {
      setSubStep(subStep - 1);
      window.scrollTo(0, 0);
    }
  };

  const formatDob = (dob: string | undefined) => {
    if (!dob) return "";
    const d = new Date(dob);
    return `${String(d.getDate()).padStart(2, "0")}/${String(d.getMonth() + 1).padStart(2, "0")}/${d.getFullYear()}`;
  };

  if (loading) return <Box p={4} display="flex" justifyContent="center"><CircularProgress /></Box>;
  if (error && !peoplePool.length && subStep === 0) return <Alert severity="error">{error}</Alert>;

  const replacementPool = peoplePool.filter((p) => !selectedAttorneyIds.includes(p.id));

  return (
    <section className="space-y-8 p-2 animate-in fade-in slide-in-from-top-4">

      {/* ═══════ SUB-STEP 0: SELECT PRIMARY ATTORNEYS ═══════ */}
      {subStep === 0 && (
        <div className="space-y-6 animate-in fade-in">
          <div className="flex flex-col md:flex-row gap-8">
            {/* Left Column - Attorney Selection */}
            <div className="flex-1 space-y-5">
              <h1 className={`text-center text-3xl font-bold text-zenco-dark ${styles.headingBorderBottom}`}>Attorneys</h1>

              <div className="flex flex-col gap-3 text-gray-600">
                <p>
                  Attorneys are people a donor appoints to make decisions on their
                  behalf, you need to choose at least one Attorney.
                </p>
              </div>

              <p className="text-lg font-semibold text-zenco-dark">Select your attorneys</p>

              {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}

              <div className="space-y-3">
                {peoplePool.map((person) => {
                  const isSelected = selectedAttorneyIds.includes(person.id);
                  return (
                    <div
                      key={person.id}
                      className={`flex items-center justify-between p-4 rounded-lg border-2 transition-all ${isSelected
                        ? "border-[#334a5e] bg-[#334a5e] text-white"
                        : "border-gray-200 bg-white hover:border-gray-300"
                        }`}
                    >
                      <div>
                        <p className="font-semibold">
                          {person.first_name} {person.last_name}
                          {person.is_lead ? " (You)" : ""}
                        </p>
                        <p className={`text-sm ${isSelected ? "text-gray-300" : "text-gray-500"}`}>
                          {formatDob(person.date_of_birth)}
                        </p>
                        <p
                          className={`text-sm underline cursor-pointer ${isSelected ? "text-blue-200 hover:text-blue-100" : "text-blue-600 hover:text-blue-800"}`}
                          onClick={(e) => {
                            e.stopPropagation();
                            openEditModal(person, "attorney");
                          }}
                        >
                          ✎ Update this person&apos;s details
                        </p>
                      </div>
                      <input
                        type="checkbox"
                        checked={isSelected}
                        onChange={() => toggleAttorney(person.id)}
                        className="w-5 h-5 cursor-pointer accent-zenco-blue"
                      />
                    </div>
                  );
                })}
              </div>

              {/* Add new attorney */}
              <button
                onClick={() => openAddModal("attorney")}
                className="w-full border-2 border-dashed border-gray-300 p-4 flex items-center justify-center gap-2 font-semibold cursor-pointer rounded-lg hover:border-gray-400 transition-all"
              >
                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="18" height="18" fill="currentColor">
                  <path d="M14 14.252V22H4C4 17.5817 7.58172 14 12 14C12.6906 14 13.3608 14.0875 14 14.252ZM12 13C8.685 13 6 10.315 6 7C6 3.685 8.685 1 12 1C15.315 1 18 3.685 18 7C18 10.315 15.315 13 12 13ZM18 17V14H20V17H23V19H20V22H18V19H15V17H18Z" />
                </svg>
                <span>Add new attorney</span>
              </button>
            </div>

            {/* Right Column - Info */}
            <div className="md:w-72 space-y-3">
              <h3 className="font-semibold text-zenco-dark">Who can be an Attorney?</h3>
              <p className="text-sm text-gray-600">The Attorney must be meet the following requirements:</p>
              <ul className="space-y-2 text-sm">
                <li className="flex items-center gap-2">
                  <svg className="w-4 h-4 text-green-500 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
                  Aged <strong>18 or over</strong>.
                </li>
                <li className="flex items-center gap-2">
                  <svg className="w-4 h-4 text-green-500 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
                <p>Have <strong>mental capacity</strong> to make decisions.</p>
                </li>
                <li className="flex items-center gap-2">
                  <svg className="w-4 h-4 text-red-500 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                <p>Must <strong>not</strong> be bankrupt, or subject to a debt relief order.</p>
                </li>
              </ul>
            </div>
          </div>
        </div>
      )}

      {/* ═══════ SUB-STEP 1: DOCUMENT VIEW AUTHORITY ═══════ */}
      {subStep === 1 && (
        <div className="space-y-6 animate-in fade-in">
          <h1 className={`text-center text-3xl font-bold text-zenco-dark ${styles.headingBorderBottom}`}>
            Can attorneys <span className="text-zenco-blue">view your legal documents?</span>
          </h1>
          <div className="flex flex-col md:flex-row gap-8">
            <div className="flex-1 space-y-6">
              <p className="text-zenco-dark text-lg font-semibold">
                Are you happy for your Attorneys to view your legal documents if you lose
                mental capacity?
              </p>

              {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}

              <div className="flex flex-col gap-0">
                <button
                  onClick={() => setCanViewDocuments(true)}
                  className={`border-2 p-4 text-center transition-all ${canViewDocuments === true
                    ? "border-[#334a5e] bg-[#334a5e] text-white font-semibold"
                    : "border-gray-300 hover:bg-gray-50"
                    }`}
                >
                  Yes - give the attorneys authority
                </button>
                <button
                  onClick={() => setCanViewDocuments(false)}
                  className={`border-2 border-t-0 p-4 text-center transition-all ${canViewDocuments === false
                    ? "border-[#334a5e] bg-[#334a5e] text-white font-semibold"
                    : "border-gray-300 hover:bg-gray-50"
                    }`}
                >
                  No - do not give the attorneys authority
                </button>
              </div>
            </div>

            {/* Right Column - Help */}
            <div className="md:w-72">
              <details className="border border-gray-200 rounded-lg">
                <summary className="p-3 font-semibold text-zenco-blue cursor-pointer">NEED HELP?</summary>
                <div className="p-3 text-sm text-gray-600">
                  <p>This gives your attorneys the authority to view your will, other LPAs, and related legal documents.</p>
                </div>
              </details>
            </div>
          </div>
        </div>
      )}

      {/* ═══════ SUB-STEP 2: REPLACEMENT ATTORNEYS ═══════ */}
      {subStep === 2 && (
        <div className="space-y-6 animate-in fade-in">
          <div className="flex flex-col md:flex-row gap-8">
            <div className="flex-1 space-y-5">
              <h1 className={`text-center text-3xl font-bold text-zenco-dark ${styles.headingBorderBottom}`}>
                Replacement <span className="text-zenco-blue">Attorneys</span>
              </h1>

              <div className="flex flex-col gap-3 text-gray-600">
                <p>One or more replacement attorneys can be appointed, this is optional.</p>
                <p>
                  Replacement attorneys are people a donor appoints to make decisions on their
                  behalf if one of their attorneys can no longer make decisions on their behalf.
                </p>
              </div>

              <p className="text-lg font-semibold text-zenco-dark">
                Do you want any replacement attorneys?
              </p>

              <div className="flex flex-col gap-0">
                <button
                  onClick={() => { setWantsReplacement(false); setSelectedReplacementIds([]); }}
                  className={`border-2 p-4 text-center transition-all ${wantsReplacement === false
                    ? "border-[#334a5e] bg-[#334a5e] text-white font-semibold"
                    : "border-gray-300 hover:bg-gray-50"
                    }`}
                >
                  No
                </button>
                <button
                  onClick={() => setWantsReplacement(true)}
                  className={`border-2 border-t-0 p-4 text-center transition-all ${wantsReplacement === true
                    ? "border-[#334a5e] bg-[#334a5e] text-white font-semibold"
                    : "border-gray-300 hover:bg-gray-50"
                    }`}
                >
                  Yes
                </button>
              </div>

              {/* Show replacement selection if Yes */}
              {wantsReplacement && (
                <div className="space-y-4 animate-in fade-in mt-4">
                  <p className="text-lg font-semibold text-zenco-dark">Select your Replacement Attorneys</p>

                  <div className="space-y-3">
                    {replacementPool.map((person) => {
                      const isSelected = selectedReplacementIds.includes(person.id);
                      return (
                        <div
                          key={person.id}
                          className={`flex items-center justify-between p-4 rounded-lg border-2 cursor-pointer transition-all ${isSelected
                            ? "border-[#334a5e] bg-white shadow-sm"
                            : "border-gray-200 bg-white hover:border-gray-300"
                            }`}
                        >
                          <div className="flex items-center gap-3">
                            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="28" height="28" fill="currentColor" className="text-gray-500">
                              <path d="M4 22C4 17.5817 7.58172 14 12 14C16.4183 14 20 17.5817 20 22H4ZM12 13C8.685 13 6 10.315 6 7C6 3.685 8.685 1 12 1C15.315 1 18 3.685 18 7C18 10.315 15.315 13 12 13Z" />
                            </svg>
                            <div>
                              <p className="font-semibold text-zenco-dark">{person.first_name} {person.last_name}</p>
                              <p
                                className="text-sm underline text-blue-600 hover:text-blue-800 cursor-pointer"
                                onClick={(e) => {
                                  e.stopPropagation();
                                  openEditModal(person, "replacement");
                                }}
                              >
                                ✎ Update this person&apos;s details
                              </p>
                            </div>
                          </div>
                          <input
                            type="checkbox"
                            checked={isSelected}
                            onChange={() => toggleReplacement(person.id)}
                            className="w-5 h-5 cursor-pointer accent-zenco-blue"
                          />
                        </div>
                      );
                    })}
                  </div>

                  {/* Add new replacement attorney */}
                  <button
                    onClick={() => openAddModal("replacement")}
                    className="w-full border-2 border-dashed border-gray-300 p-4 flex items-center justify-center gap-2 font-semibold cursor-pointer rounded-lg hover:border-gray-400 transition-all"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="18" height="18" fill="currentColor">
                      <path d="M14 14.252V22H4C4 17.5817 7.58172 14 12 14C12.6906 14 13.3608 14.0875 14 14.252ZM12 13C8.685 13 6 10.315 6 7C6 3.685 8.685 1 12 1C15.315 1 18 3.685 18 7C18 10.315 15.315 13 12 13ZM18 17V14H20V17H23V19H20V22H18V19H15V17H18Z" />
                    </svg>
                    <span>Add new replacement attorney</span>
                  </button>
                </div>
              )}
            </div>

            {/* Right Column - Info */}
            <div className="md:w-72 space-y-3">
              <h3 className="font-semibold text-zenco-dark">Who can be a Replacement Attorney?</h3>
              <p className="text-sm text-gray-600">The replacement attorney must be meet the following requirements:</p>
              <ul className="space-y-2 text-sm">
                <li className="flex items-center gap-2">
                  <svg className="w-4 h-4 text-green-500 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
                  Aged <strong>18 or over</strong>.
                </li>
                <li className="flex items-center gap-2">
                  <svg className="w-4 h-4 text-green-500 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
                 <p>Have <strong>mental capacity</strong> to make decisions.</p>
                </li>
                <li className="flex items-center gap-2">
                  <svg className="w-4 h-4 text-red-500 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                  <p>Must <strong>not</strong> be bankrupt, or subject to a debt relief order.</p>
                </li>
                <li className="flex items-center gap-2">
                  <svg className="w-4 h-4 text-red-500 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                  <p>Must not already be assigned as an <strong>Attorney</strong></p>
                </li>
              </ul>
            </div>
          </div>
        </div>
      )}

      {/* ═══════ INTERNAL NAVIGATION ═══════ */}
      <div className="flex justify-between pt-6">
        <Button
          onClick={handleInternalBack}
          sx={{ color: "#6b7280", textTransform: "none", opacity: subStep === 0 ? 0 : 1 }}
          disabled={subStep === 0}
        >
          ← Back
        </Button>

        <Button
          variant="contained"
          onClick={handleInternalNext}
          disabled={isSubmitting}
          sx={{
            backgroundColor: "#08B9ED",
            textTransform: "none",
            borderRadius: "8px",
            padding: "8px 32px",
            "&:hover": { backgroundColor: "#1d4ed8" },
          }}
        >
          {isSubmitting ? <CircularProgress size={24} color="inherit" /> : "Save and continue"}
        </Button>
      </div>

      {/* ═══════ ADD / EDIT PERSON MODAL ═══════ */}
      <Dialog open={openModal} onClose={() => setOpenModal(false)} fullWidth maxWidth="sm">
        <div className="flex justify-between items-center px-4 py-2 bg-[#334a5e]">
          <DialogTitle className="text-white !p-0 !text-lg">
            {editingPersonId
              ? "Update person's details"
              : modalMode === "attorney"
                ? "Add attorney"
                : "Add replacement attorney"}
          </DialogTitle>
          <span className="hover:cursor-pointer text-white" onClick={() => setOpenModal(false)}>
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="22" height="22" fill="currentColor">
              <path d="M11.9997 10.5865L16.9495 5.63672L18.3637 7.05093L13.4139 12.0007L18.3637 16.9504L16.9495 18.3646L11.9997 13.4149L7.04996 18.3646L5.63574 16.9504L10.5855 12.0007L5.63574 7.05093L7.04996 5.63672L11.9997 10.5865Z" />
            </svg>
          </span>
        </div>

        <DialogContent className="flex flex-col gap-5 mt-4">
          <p className="text-xl font-semibold text-zenco-dark">Full legal name</p>

          <FormControl fullWidth>
            <InputLabel>Title</InputLabel>
            <Select value={formData.title} label="Title" onChange={(e) => setFormData({ ...formData, title: e.target.value })}>
              {["Mr", "Mrs", "Miss", "Ms", "Mx", "Dr", "Rev", "Prof", "Lady", "Lord"].map((t) => (
                <MenuItem key={t} value={t}>{t}</MenuItem>
              ))}
            </Select>
          </FormControl>

          <div className="grid grid-cols-2 gap-4">
            <TextField label="First Name" fullWidth value={formData.firstName} onChange={(e) => setFormData({ ...formData, firstName: e.target.value })} />
            <TextField label="Last Name" fullWidth value={formData.lastName} onChange={(e) => setFormData({ ...formData, lastName: e.target.value })} />
          </div>

          <TextField label="Middle names (if any)" fullWidth value={formData.middleName} onChange={(e) => setFormData({ ...formData, middleName: e.target.value })} />

          <p className="text-xl font-semibold text-zenco-dark">What&apos;s their address?</p>
          <div className="flex gap-4 items-end">
            <TextField
              label="Postcode"
              fullWidth
              value={formData.postcode}
              onChange={(e) => setFormData({ ...formData, postcode: e.target.value })}
            />
            <Button
              variant="contained"
              sx={{
                backgroundColor: "#08B9ED",
                textTransform: "none",
                borderRadius: "8px",
                height: "56px",
                "&:hover": { backgroundColor: "#07bdf5ff" },
              }}
            >
              Search
            </Button>
          </div>

          {!showManualAddress && (
            <button
              type="button"
              onClick={() => setShowManualAddress(true)}
              className="text-cyan-500 font-semibold text-sm hover:underline text-left w-fit"
            >
              Enter address manually
            </button>
          )}

          {showManualAddress && (
            <div className="space-y-5 animate-in fade-in slide-in-from-top-2">
              <TextField
                label="Address Line 1"
                fullWidth
                value={formData.addressLine1}
                onChange={(e) => setFormData({ ...formData, addressLine1: e.target.value })}
              />
              <TextField
                label="Address Line 2 (Optional)"
                fullWidth
                value={formData.addressLine2}
                onChange={(e) => setFormData({ ...formData, addressLine2: e.target.value })}
              />
              <div className="grid grid-cols-2 gap-4">
                <TextField
                  label="City"
                  fullWidth
                  value={formData.city}
                  onChange={(e) => setFormData({ ...formData, city: e.target.value })}
                />
                <TextField
                  label="County (Optional)"
                  fullWidth
                  value={formData.county}
                  onChange={(e) => setFormData({ ...formData, county: e.target.value })}
                />
              </div>
            </div>
          )}

          <p className="text-xl font-semibold text-zenco-dark">What&apos;s their date of birth?</p>
          <TextField type="date" fullWidth InputLabelProps={{ shrink: true }} value={formData.dob} onChange={(e) => setFormData({ ...formData, dob: e.target.value })} />

          <p className="text-xl font-semibold text-zenco-dark">What&apos;s their email address? (optional)</p>
          <TextField label="Email" fullWidth value={formData.email} onChange={(e) => setFormData({ ...formData, email: e.target.value })} />
        </DialogContent>

        <DialogActions className="p-4">
          <Button
            fullWidth
            variant="contained"
            onClick={handleSaveModal}
            disabled={isSubmitting}
            sx={{
              backgroundColor: "#08B9ED",
              textTransform: "none",
              borderRadius: "8px",
              padding: "12px",
              fontWeight: 600,
              "&:hover": { backgroundColor: "#1d4ed8" },
            }}
          >
            {isSubmitting ? <CircularProgress size={24} color="inherit" /> : "Save and continue"}
          </Button>
        </DialogActions>
      </Dialog>
    </section>
  );
}

"use client";

import { useState, useEffect } from "react";
import {
  Button,
  Box,
  CircularProgress,
  Alert,
} from "@mui/material";
import { supabase } from "@/lib/supabase";
import styles from "./Steps.module.css";

type LpaDoc = {
  id: string;
  donor_id: string;
  lpa_type: "health_and_welfare" | "property_and_finance";
  life_sustaining_treatment?: boolean | null;
  when_attorneys_can_act?: string | null;
};

type Props = {
  data: any;
  updateData: (data: any) => void;
  onNext: () => void;
  isSaving: boolean;
  allFormData: any;
  currentDonorIndex: number;
};

export default function HealthFinanceTab({ onNext, isSaving, allFormData, updateData, currentDonorIndex }: Props) {
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [donorName, setDonorName] = useState("");
  const [donorFirstName, setDonorFirstName] = useState("");

  const [lpaDocs, setLpaDocs] = useState<LpaDoc[]>([]);
  const hasHealth = lpaDocs.some((d) => d.lpa_type === "health_and_welfare");
  const hasFinance = lpaDocs.some((d) => d.lpa_type === "property_and_finance");

  const [subStep, setSubStep] = useState(0);


  const [lifeSustaining, setLifeSustaining] = useState<boolean | null>(null);

  const [whenCanAct, setWhenCanAct] = useState<"when_registered" | "loss_of_capacity" | null>(null);

  const applicationId = allFormData?.who?.applicationId;

  useEffect(() => {
    const init = async () => {
      if (!applicationId) { setLoading(false); return; }
      try {
        const { data: { session } } = await supabase.auth.getSession();
        if (!session) return;
        const token = session.access_token;

        const donorsRes = await fetch(`/api/donors?applicationId=${applicationId}`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        const { data: donors } = await donorsRes.json();

        if (!donors || donors.length === 0) {
          setLoading(false);
          return;
        }

        const step1Selection = allFormData?.who?.selection;
        const step1SelectedIds = allFormData?.who?.selectedPeopleIds || [];
        const isLeadSelected =
          step1Selection === "You" ||
          step1Selection === "You and your partner" ||
          step1Selection === "You and someone else";

        const activeDonors = donors.filter((d: any) => {
          if (d.is_lead) return isLeadSelected;
          return step1SelectedIds.includes(d.id);
        });

        const firstDonor = activeDonors[currentDonorIndex];
        if (!firstDonor) {
          setLoading(false);
          return;
        }

        setDonorName(`${firstDonor.first_name} ${firstDonor.last_name}`);
        setDonorFirstName(firstDonor.first_name);

        const lpasRes = await fetch(`/api/lpa-documents?donorId=${firstDonor.id}`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        const { data: docs } = await lpasRes.json();

        if (docs && Array.isArray(docs) && docs.length > 0) {
          setLpaDocs(docs);

          const healthDoc = docs.find((d: any) => d.lpa_type === "health_and_welfare");
          const financeDoc = docs.find((d: any) => d.lpa_type === "property_and_finance");

          if (healthDoc?.life_sustaining_treatment !== null && healthDoc?.life_sustaining_treatment !== undefined) {
            setLifeSustaining(healthDoc.life_sustaining_treatment);
          }
          if (financeDoc?.when_attorneys_can_act) {
            setWhenCanAct(financeDoc.when_attorneys_can_act as "when_registered" | "loss_of_capacity");
          }
        }

        const saved = allFormData?.["health-&-finances"];
        if (saved) {
          if (saved.lifeSustaining !== undefined && saved.lifeSustaining !== null) setLifeSustaining(saved.lifeSustaining);
          if (saved.whenCanAct) setWhenCanAct(saved.whenCanAct);
        }
      } catch (err) {
        console.error("Error loading Step 5:", err);
        setError("Failed to load health & finance details.");
      } finally {
        setLoading(false);
      }
    };
    init();
  }, [applicationId, currentDonorIndex, allFormData?.who]);

  const pages: ("health" | "finance")[] = [];
  if (hasHealth) pages.push("health");
  if (hasFinance) pages.push("finance");
  const currentPage = pages[subStep] || null;
  const handleInternalNext = async () => {
    if (currentPage === "health") {
      if (lifeSustaining === null) {
        setError("Please select an option.");
        return;
      }
      setError(null);
      if (subStep < pages.length - 1) {
        setSubStep(subStep + 1);
        window.scrollTo(0, 0);
        return;
      }
    }

    if (currentPage === "finance") {
      if (whenCanAct === null) {
        setError("Please select an option.");
        return;
      }
      setError(null);
    }

    setIsSubmitting(true);
    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) return;
      const token = session.access_token;

      const healthDoc = lpaDocs.find((d) => d.lpa_type === "health_and_welfare");
      if (healthDoc && lifeSustaining !== null) {
        await fetch("/api/lpa-documents", {
          method: "PATCH",
          headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` },
          body: JSON.stringify({
            id: healthDoc.id,
            life_sustaining_treatment: lifeSustaining,
          }),
        });
      }

      const financeDoc = lpaDocs.find((d) => d.lpa_type === "property_and_finance");
      if (financeDoc && whenCanAct !== null) {
        await fetch("/api/lpa-documents", {
          method: "PATCH",
          headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` },
          body: JSON.stringify({
            id: financeDoc.id,
            when_attorneys_can_act: whenCanAct,
          }),
        });
      }

      updateData({
        lifeSustaining,
        whenCanAct,
      });

      onNext();
    } catch (err) {
      console.error("Error saving health & finance:", err);
      setError("Failed to save. Please try again.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleInternalBack = () => {
    if (subStep > 0) {
      setSubStep(subStep - 1);
      window.scrollTo(0, 0);
    }
  };

  if (loading) return <Box p={4} display="flex" justifyContent="center"><CircularProgress /></Box>;

  if (pages.length === 0) {
    return (
      <Alert severity="info">
        No LPA documents found for the current donor. Please go back and select a document type in Step 2.
      </Alert>
    );
  }

  return (
    <section className="space-y-8 animate-in fade-in slide-in-from-top-4">

      {/* ═══════ HEALTH & WELFARE: LIFE-SUSTAINING TREATMENT ═══════ */}
      {currentPage === "health" && (
        <div className="space-y-6 animate-in fade-in">
          <h1 className={`text-center text-3xl font-bold text-zenco-dark ${styles.headingBorderBottom}`}>
            Life-sustaining <span className="text-zenco-blue">Treatment</span>
          </h1>
          <div className="flex flex-col gap-3 text-gray-700">
            <p>
              <span className="text-zenco-blue font-semibold">{donorName}</span>{" "}
              must choose what they want to happen if they needed medical help to keep them alive and
              they no longer had mental capacity.
            </p>
            <p>
              If they choose YES and{" "}
              <span className="text-zenco-blue font-semibold">{donorName}</span>{" "}
              ever needed life-sustaining treatment but can&apos;t make decisions, the
              attorneys can speak to doctors on their behalf as if they were{" "}
              <span className="text-zenco-blue font-semibold">{donorName}</span>.
            </p>
            <p>
              If you choose NO doctors will make decisions about life-sustaining treatment for{" "}
              <span className="text-zenco-blue font-semibold">{donorName}</span>.
            </p>
          </div>

          <p className="text-xl font-semibold text-zenco-dark">
            Do you want the attorneys to make decisions about life-sustaining treatment?
          </p>

          {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}

          <div className="flex flex-col gap-0 max-w-xl">
            <button
              onClick={() => setLifeSustaining(true)}
              className={`border-2 p-4 text-center transition-all ${lifeSustaining === true
                ? "border-[#334a5e] bg-[#334a5e] text-white font-semibold"
                : "border-gray-300 hover:bg-gray-50"
                }`}
            >
              Yes - give the attorneys authority
            </button>
            <button
              onClick={() => setLifeSustaining(false)}
              className={`border-2 border-t-0 p-4 text-center transition-all ${lifeSustaining === false
                ? "border-[#334a5e] bg-[#334a5e] text-white font-semibold"
                : "border-gray-300 hover:bg-gray-50"
                }`}
            >
              No - do not give the attorneys authority
            </button>
          </div>
        </div>
      )}

      {/* ═══════ PROPERTY & FINANCE: WHEN ATTORNEYS CAN ACT ═══════ */}
      {currentPage === "finance" && (
        <div className="space-y-6 animate-in fade-in">
          <h1 className={`text-center text-3xl font-bold text-zenco-dark ${styles.headingBorderBottom}`}>
            When do the <span className="text-zenco-blue">property and finance documents become effective?</span>
          </h1>

          <div className="flex flex-col gap-4 text-gray-700">
            <p>
              {donorName} can choose to allow the attorneys to make decisions either:
            </p>
            <ul className="list-disc ml-6 space-y-1">
              <li>
                As soon as the lasting power of attorney has been registered by the Office of the Public Guardian
              </li>
              <li>
                Only when {donorFirstName} doesn&apos;t have mental capacity
              </li>
            </ul>

            <p className="text-zenco-blue text-sm italic">
              Most people choose the first option of &apos;As soon as the lasting power of attorney has been registered&apos;.
            </p>
          </div>

          <p className="text-xl font-semibold text-zenco-dark">
            When do you want the attorneys to be able to make decisions?
          </p>

          {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}

          <div className="flex flex-col gap-4 max-w-2xl">
            {/* Option 1: As soon as registered */}
            <div
              onClick={() => setWhenCanAct("when_registered")}
                className={`border-2 p-5 rounded-lg cursor-pointer transition-all ${whenCanAct === "when_registered"
                ? "border-[#334a5e] bg-[#334a5e] text-white shadow-md"
                : "border-gray-300 hover:border-gray-400"
                }`}
            >
              <div className="flex items-start justify-between gap-4">
                <div className="flex-1 space-y-2">
                  <p className={`font-semibold  ${whenCanAct === "when_registered"
                ? "text-white"
                : " text-zenco-dark"}`}>
                    As soon as the lasting power of attorney has been registered
                  </p>
                  <p className={`text-sm  ${whenCanAct === "when_registered"
                ? "text-white"
                : " text-gray-500"
                }`}>
                    (and also when the donor does not have the mental capacity)
                  </p>
                  <p className={`text-sm  ${whenCanAct === "when_registered"
                ? "text-white"
                : " text-zenco-blue"
                }`}>
                    Most people choose this option because it is the most practical
                  </p>
                  <p className={`text-sm  ${whenCanAct === "when_registered"
                ? "text-white"
                : "text-gray-500"
                }`}>
                    While you still have mental capacity, attorneys can only act with your consent. If you
                    later lose capacity, they can continue to act on your behalf for all decisions covered by
                    this lasting power of attorney.
                  </p>
                </div>
                <input
                  type="checkbox"
                  checked={whenCanAct === "when_registered"}
                  onChange={() => { }}
                  className="w-5 h-5 mt-1 cursor-pointer accent-zenco-blue flex-shrink-0"
                />
              </div>
            </div>

            {/* Option 2: Only when donor loses mental capacity */}
            <div
              onClick={() => setWhenCanAct("loss_of_capacity")}
              className={`border-2 p-5 rounded-lg cursor-pointer transition-all ${whenCanAct === "loss_of_capacity"
                ? "border-[#334a5e] bg-[#334a5e] text-white shadow-md"
                : "border-gray-300 hover:border-gray-400"
                }`}
            >
              <div className="flex items-start justify-between gap-4">
                <div className="flex-1 space-y-2">
                  <p className={`font-semibold ${whenCanAct === "loss_of_capacity" ? "text-white" : "text-zenco-dark"}`}>
                    Only when the donor does not have mental capacity
                  </p>
                  <p className={`text-sm ${whenCanAct === "loss_of_capacity" ? "text-gray-200" : "text-gray-600"}`}>
                    This can make your lasting power of attorney less useful. Your attorneys might be
                    asked to prove you do not have the mental capacity each time they try to use the
                    lasting power of attorney.
                  </p>
                </div>
                <input
                  type="checkbox"
                  checked={whenCanAct === "loss_of_capacity"}
                  onChange={() => { }}
                  className="w-5 h-5 mt-1 cursor-pointer accent-zenco-blue flex-shrink-0"
                />
              </div>
            </div>
          </div>
        </div>
      )}

      {/* ═══════ INTERNAL NAVIGATION ═══════ */}
      <div className="flex justify-between pt-6">
        <Button
          onClick={handleInternalBack}
          sx={{ color: "#6b7280", textTransform: "none", opacity: subStep === 0 ? 0 : 1 }}
          disabled={subStep === 0}
        >
          ← Back
        </Button>

        <Button
          variant="contained"
          onClick={handleInternalNext}
          disabled={isSubmitting}
          sx={{
            backgroundColor: "#08B9ED",
            textTransform: "none",
            borderRadius: "8px",
            padding: "8px 32px",
            "&:hover": { backgroundColor: "#1d4ed8" },
          }}
        >
          {isSubmitting ? <CircularProgress size={24} color="inherit" /> : "Save and continue"}
        </Button>
      </div>
    </section>
  );
}

"use client";
import {
  SquarePen,
  UserPlus,
  UserRound,
  X,
  Trash2,
} from "lucide-react";
import { useState, useEffect } from "react";
import styles from "./Steps.module.css";
import { supabase } from "@/lib/supabase";
import { CircularProgress, Alert } from "@mui/material";

type Person = {
  id: string;
  lpa_document_id: string;
  title: string;
  first_name: string;
  last_name: string;
  address_line_1: string;
  city: string;
  postcode: string;
  deleted_at?: string | null;
};

type Props = {
  onNext: () => void;
  isSaving: boolean;
  allFormData: any;
  updateData: (data: any) => void;
  currentDonorIndex: number;
};

export default function PeopleToNotifyTab({ onNext, isSaving, allFormData, updateData, currentDonorIndex }: Props) {
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [hasPeople, setHasPeople] = useState<boolean | null>(null);
  const [showModal, setShowModal] = useState(false);
  const [people, setPeople] = useState<Person[]>([]);
  const [editingPerson, setEditingPerson] = useState<Person | null>(null);

  const applicationId = allFormData?.who?.applicationId;
  const donorId = allFormData?.["which-donor"]?.donorId;
  const [lpaDocId, setLpaDocId] = useState<string | null>(null);

  const [formData, setFormData] = useState({
    title: "Mr",
    first_name: "",
    last_name: "",
    address_line_1: "",
    city: "",
    postcode: "",
  });

  useEffect(() => {
    const init = async () => {
      if (!donorId) {
        setLoading(false);
        return;
      }

      try {
        const { data: { session } } = await supabase.auth.getSession();
        if (!session) return;
        const token = session.access_token;

        const donorsRes = await fetch(`/api/donors?applicationId=${applicationId}`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        const { data: fetchedDonors } = await donorsRes.json();

        let activeDonorId = donorId;
        if (fetchedDonors) {
          const step1Selection = allFormData?.who?.selection;
          const step1SelectedIds = allFormData?.who?.selectedPeopleIds || [];
          const isLeadSelected =
            step1Selection === "You" ||
            step1Selection === "You and your partner" ||
            step1Selection === "You and someone else";

          const activeDonors = fetchedDonors.filter((d: any) => {
            if (d.is_lead) return isLeadSelected;
            return step1SelectedIds.includes(d.id);
          });
          activeDonorId = activeDonors[currentDonorIndex]?.id;
        }

        if (!activeDonorId) {
          setLoading(false);
          return;
        }

        const lpaDocsRes = await fetch(`/api/lpa-documents?donorId=${activeDonorId}`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        const { data: lpaDocs } = await lpaDocsRes.json();

        if (lpaDocs && lpaDocs.length > 0) {
          const firstLpaId = lpaDocs[0].id;
          setLpaDocId(firstLpaId);

          const peopleRes = await fetch(`/api/people-to-notify?lpaDocId=${firstLpaId}`, {
            headers: { Authorization: `Bearer ${token}` },
          });
          const { data: fetchedPeople } = await peopleRes.json();

          if (fetchedPeople) {
            setPeople(fetchedPeople);
            setHasPeople(fetchedPeople.length > 0);
          }
        }

        if (allFormData["people-to-Notify"]?.hasPeople !== undefined) {
          setHasPeople(allFormData["people-to-Notify"].hasPeople);
        }

      } catch (err) {
        console.error("Error loading people to notify:", err);
        setError("Failed to load data.");
      } finally {
        setLoading(false);
      }
    };

    init();
  }, [applicationId, currentDonorIndex, allFormData?.who]);

  useEffect(() => {
    if (isSaving) {
      handleSaveAndNext();
    }
  }, [isSaving]);

  const handleSaveAndNext = () => {
    updateData({ hasPeople, people });
    onNext();
  };

  const openAddModal = () => {
    setEditingPerson(null);
    setFormData({
      title: "Mr",
      first_name: "",
      last_name: "",
      address_line_1: "",
      city: "",
      postcode: "",
    });
    setShowModal(true);
  };

  const openEditModal = (person: Person) => {
    setEditingPerson(person);
    setFormData({
      title: person.title,
      first_name: person.first_name,
      last_name: person.last_name,
      address_line_1: person.address_line_1,
      city: person.city,
      postcode: person.postcode,
    });
    setShowModal(true);
  };

  const handleSavePerson = async () => {
    if (!lpaDocId) return;
    if (!formData.first_name || !formData.last_name) {
      alert("First and last name are required.");
      return;
    }

    setIsSubmitting(true);
    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) return;
      const token = session.access_token;

      if (editingPerson) {
        const res = await fetch("/api/people-to-notify", {
          method: "PATCH",
          headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` },
          body: JSON.stringify({ id: editingPerson.id, ...formData }),
        });
        const { data: updated } = await res.json();
        if (updated) {
          setPeople((prev) => prev.map((p) => (p.id === updated.id ? updated : p)));
        }
      } else {
        if (people.length >= 5) {
          alert("Maximum 5 people to notify allowed per document.");
          setIsSubmitting(false);
          return;
        }

        const res = await fetch("/api/people-to-notify", {
          method: "POST",
          headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` },
          body: JSON.stringify({ lpa_document_id: lpaDocId, ...formData }),
        });
        const { data: created } = await res.json();
        if (created) {
          setPeople((prev) => [...prev, created]);
        }
      }

      setShowModal(false);
    } catch (err) {
      console.error("Error saving person:", err);
      alert("Failed to save person.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDeletePerson = async (id: string) => {
    if (!confirm("Are you sure you want to remove this person?")) return;

    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) return;
      const token = session.access_token;

      const res = await fetch(`/api/people-to-notify?id=${id}`, {
        method: "DELETE",
        headers: { Authorization: `Bearer ${token}` },
      });
      const result = await res.json();

      if (result.success) {
        setPeople((prev) => prev.filter((p) => p.id !== id));
      }
    } catch (err) {
      console.error("Error deleting person:", err);
      alert("Failed to delete person.");
    }
  };

  if (loading) return <div className="flex justify-center p-10"><CircularProgress /></div>;

  return (
    <>
      <main className="grow flex justify-center">
        <div className="max-w-6xl w-full grid grid-cols-1 gap-10">
          <div className="lg:col-span-2">
            <h4 className={styles.stepHeading}>
              People to notify
            </h4>

            <div className={styles.dividerZenco}></div>

            <p className={styles.pZenco}>
              You can let people know that you're going to register this document. They can raise any concerns they have about the
              Lasting Powers of Attorney-for example, if there was any pressure or fraud in making it.
            </p>
            <p className={styles.pZenco}>
              When the document is registered, the person applying to register must send a notice to each 'person to notify'.
            </p>
            <p className={styles.pZenco}>
              You can't put any of the attorneys or replacement attorneys here.
            </p>
            <p className={styles.pZenco}>
              Choose people who care about your best interests and who would be willing to speak up if they were concerned.
            </p>

            <div className="text-zenco-blue font-medium mb-8">
              Most people choose 'No' and do not enter anyone here.
            </div>

            <div className="mx-auto">
              <h2 className="font-bold text-lg my-4">
                Are there any people to notify?
              </h2>

              <div className="space-y-3">
                <button
                  onClick={() => setHasPeople(false)}
                  className={hasPeople === false ? styles.btnDark : styles.btnWhite}
                >
                  No, there are no people to notify
                </button>
                <button
                  onClick={() => setHasPeople(true)}
                  className={hasPeople === true ? styles.btnDark : styles.btnWhite}
                >
                  Yes, there are people to notify
                </button>
              </div>

              {hasPeople === true && (
                <div className="mt-8 animate-in fade-in">
                  <button
                    onClick={openAddModal}
                    disabled={people.length >= 5}
                    className={`${styles.btnWhite} mb-6 ${people.length >= 5 ? 'opacity-50 cursor-not-allowed' : ''}`}
                  >
                    <UserPlus size={18} />
                    Add new person to notify
                  </button>

                  {people.length >= 5 && (
                    <Alert severity="warning" className="mb-4">
                      You have reached the maximum limit of 5 people to notify.
                    </Alert>
                  )}

                  {people.length > 0 && (
                    <>
                      <h2 className="font-bold text-lg my-4">
                        People to notify
                      </h2>

                      <div className="space-y-3">
                        {people.map((person) => (
                          <div
                            key={person.id}
                            className="flex justify-between items-center p-4 border rounded-lg bg-white shadow-sm hover:shadow-md transition"
                          >
                            <div className="flex items-center gap-3">
                              <UserRound size={30} className="text-gray-400" />
                              <div>
                                <p className="font-bold text-zenco-dark text-lg">
                                  {person.title} {person.first_name} {person.last_name}
                                </p>
                                <p className="text-sm text-gray-600">
                                  {person.address_line_1}, {person.city}, {person.postcode}
                                </p>

                                <div className="flex gap-4 mt-1">
                                  <p
                                    onClick={() => openEditModal(person)}
                                    className="text-sm flex items-center gap-1 text-blue-600 hover:underline cursor-pointer"
                                  >
                                    <SquarePen size={13} />
                                    Update details
                                  </p>
                                  <p
                                    onClick={() => handleDeletePerson(person.id)}
                                    className="text-sm flex items-center gap-1 text-red-600 hover:underline cursor-pointer"
                                  >
                                    <Trash2 size={13} />
                                    Remove
                                  </p>
                                </div>
                              </div>
                            </div>
                          </div>
                        ))}
                      </div>
                    </>
                  )}
                </div>
              )}
            </div>
          </div>
        </div>
      </main>

      {showModal && (
        <div className="fixed inset-0 bg-black/40 flex items-center justify-center z-50 p-4">
          <div className="bg-white w-full max-w-md rounded shadow-lg overflow-hidden animate-in zoom-in-95">
            {/* Header */}
            <div className="bg-[#3b5c77] text-white flex justify-between items-center px-4 py-3">
              <h3 className="font-semibold">{editingPerson ? "Update person" : "Add person"}</h3>
              <X
                className="cursor-pointer hover:rotate-90 transition"
                onClick={() => setShowModal(false)}
              />
            </div>

            {/* Body */}
            <div className="p-5 space-y-4">
              <div>
                <label className="text-sm font-semibold block mb-1">Title</label>
                <select
                  className="w-full border p-2 rounded mb-3 focus:ring-2 focus:ring-blue-500 outline-none"
                  value={formData.title}
                  onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                >
                  {["Mr", "Mrs", "Miss", "Ms", "Mx", "Dr", "Rev", "Prof", "Lady", "Lord"].map((t) => (
                    <option key={t} value={t}>{t}</option>
                  ))}
                </select>

                <div className="flex gap-3">
                  <div className="flex-1">
                    <label className="text-sm font-semibold block mb-1">First Name</label>
                    <input
                      className="w-full border p-2 rounded focus:ring-2 focus:ring-blue-500 outline-none"
                      value={formData.first_name}
                      onChange={(e) => setFormData({ ...formData, first_name: e.target.value })}
                    />
                  </div>
                  <div className="flex-1">
                    <label className="text-sm font-semibold block mb-1">Last Name</label>
                    <input
                      className="w-full border p-2 rounded focus:ring-2 focus:ring-blue-500 outline-none"
                      value={formData.last_name}
                      onChange={(e) => setFormData({ ...formData, last_name: e.target.value })}
                    />
                  </div>
                </div>
              </div>

              <div>
                <label className="text-sm font-semibold block mb-1">Address Line 1</label>
                <input
                  className="w-full border p-2 rounded mb-3 focus:ring-2 focus:ring-blue-500 outline-none"
                  value={formData.address_line_1}
                  onChange={(e) => setFormData({ ...formData, address_line_1: e.target.value })}
                />

                <div className="flex gap-3">
                  <div className="flex-1">
                    <label className="text-sm font-semibold block mb-1">City</label>
                    <input
                      className="w-full border p-2 rounded focus:ring-2 focus:ring-blue-500 outline-none"
                      value={formData.city}
                      onChange={(e) => setFormData({ ...formData, city: e.target.value })}
                    />
                  </div>
                  <div className="flex-1">
                    <label className="text-sm font-semibold block mb-1">Postcode</label>
                    <input
                      className="w-full border p-2 rounded focus:ring-2 focus:ring-blue-500 outline-none"
                      value={formData.postcode}
                      onChange={(e) => setFormData({ ...formData, postcode: e.target.value })}
                    />
                  </div>
                </div>
              </div>

              <button
                onClick={handleSavePerson}
                disabled={isSubmitting}
                className="w-full bg-[#00a8cc] hover:bg-[#008aaa] text-white py-3 rounded font-semibold transition-colors flex justify-center items-center gap-2"
              >
                {isSubmitting ? <CircularProgress size={20} color="inherit" /> : "Save and continue"}
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
}

"use client";

import { useState, useEffect } from "react";
import styles from "./Steps.module.css";
import { supabase } from "@/lib/supabase";
import { CircularProgress, Alert } from "@mui/material";

type ApplicantRecord = {
  id: string;
  name: string;
  email: string;
  role: "donor" | "attorney";
};

type Props = {
  data: any;
  updateData: (data: any) => void;
  onNext: () => void;
  isSaving: boolean;
  allFormData: any;
  currentDonorIndex: number;
};

export default function ApplicationInfoTab({ onNext, isSaving, allFormData, updateData, currentDonorIndex }: Props) {
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [donorRecord, setDonorRecord] = useState<ApplicantRecord | null>(null);
  const [attorneyRecords, setAttorneyRecords] = useState<ApplicantRecord[]>([]);

  const [currentView, setCurrentView] = useState<"applying" | "receiving">("applying");
  const [selectedRole, setSelectedRole] = useState<"donor" | "attorney">("donor");
  const [selectedAttorneyId, setSelectedAttorneyId] = useState<string>("");
  const [isChecked, setIsChecked] = useState(false);
  const [selectedRecipientType, setSelectedRecipientType] = useState<string>("donor");
  const [selectedRecipientId, setSelectedRecipientId] = useState<string>("");
  const [otherPeople, setOtherPeople] = useState<ApplicantRecord[]>([]);

  const applicationId = allFormData?.who?.applicationId;
  const donorId = allFormData?.["which-donor"]?.donorId;
  const [lpaDocId, setLpaDocId] = useState<string | null>(null);

  useEffect(() => {
    const init = async () => {
      if (!donorId) {
        setLoading(false);
        return;
      }

      try {
        const { data: { session } } = await supabase.auth.getSession();
        if (!session) return;
        const token = session.access_token;

        const donorsRes = await fetch(`/api/donors?applicationId=${applicationId}`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        const { data: fetchedDonors } = await donorsRes.json();

        let activeDonorId = donorId;
        if (fetchedDonors) {
          const step1Selection = allFormData?.who?.selection;
          const step1SelectedIds = allFormData?.who?.selectedPeopleIds || [];
          const isLeadSelected =
            step1Selection === "You" ||
            step1Selection === "You and your partner" ||
            step1Selection === "You and someone else";

          const activeDonors = fetchedDonors.filter((d: any) => {
            if (d.is_lead) return isLeadSelected;
            return step1SelectedIds.includes(d.id);
          });
          activeDonorId = activeDonors[currentDonorIndex]?.id;
        }

        if (!activeDonorId) {
          setLoading(false);
          return;
        }

        const lpaDocsRes = await fetch(`/api/lpa-documents?donorId=${activeDonorId}`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        const { data: lpaDocs } = await lpaDocsRes.json();

        if (!lpaDocs || lpaDocs.length === 0) {
          setError("No LPA documents found for this donor.");
          setLoading(false);
          return;
        }

        const activeLpaId = lpaDocs[0].id;
        setLpaDocId(activeLpaId);

        const donor = fetchedDonors?.find((d: any) => d.id === activeDonorId);

        if (donor) {
          setDonorRecord({
            id: donor.id,
            name: `${donor.first_name} ${donor.last_name}`,
            email: donor.email || "No email provided",
            role: "donor"
          });
        }

        const attorneysRes = await fetch(`/api/lpa-document-attorneys?lpaDocId=${activeLpaId}`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        const { data: junctionRows } = await attorneysRes.json();

        let primaryAttorneys: ApplicantRecord[] = [];
        if (junctionRows) {
          primaryAttorneys = junctionRows
            .filter((row: any) => row.role === "primary")
            .map((row: any) => ({
              id: row.attorneys.id,
              name: `${row.attorneys.first_name} ${row.attorneys.last_name}`,
              email: row.attorneys.email || "No email provided",
              role: "attorney" as const
            }));
          setAttorneyRecords(primaryAttorneys);
          if (primaryAttorneys.length > 0) {
            setSelectedAttorneyId(primaryAttorneys[0].id);
          }
        }

        // Fetch other people (e.g. for Notify)
        const notifyRes = await fetch(`/api/people-to-notify?lpaDocId=${activeLpaId}`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        const { data: notifyPeople } = await notifyRes.json();
        const notifyList = (notifyPeople || []).map((p: any) => ({
          id: p.id,
          name: `${p.first_name} ${p.last_name}`,
          email: p.email || "No email provided",
          role: "notify" as any
        }));

        setOtherPeople(notifyList);

        const applicantRes = await fetch(`/api/lpa-document-applicants?lpaDocId=${activeLpaId}`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        const { data: existingApplicants } = await applicantRes.json();

        if (existingApplicants && existingApplicants.length > 0) {
          const first = existingApplicants[0];
          setSelectedRole(first.applicant_role);
          if (first.applicant_role === "attorney") {
            setSelectedAttorneyId(first.attorney_id);
          }
          setIsChecked(true);
        }

      } catch (err) {
        console.error("Error loading applicant data:", err);
        setError("Failed to load application details.");
      } finally {
        setLoading(false);
      }
    };

    init();
  }, [applicationId, currentDonorIndex, allFormData?.who]);

  useEffect(() => {
    if (isSaving) {
      handleSave();
    }
  }, [isSaving]);

  const handleSave = async () => {
    if (currentView === "applying") {
      setCurrentView("receiving");
      return;
    }

    if (!lpaDocId || !isChecked) {
      onNext();
      return;
    }

    setIsSubmitting(true);
    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) return;
      const token = session.access_token;

      await fetch(`/api/lpa-document-applicants?lpaDocId=${lpaDocId}`, {
        method: "DELETE",
        headers: { Authorization: `Bearer ${token}` },
      });

      const attorneyId = selectedRole === "attorney" ? selectedAttorneyId : null;

      await fetch("/api/lpa-document-applicants", {
        method: "POST",
        headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` },
        body: JSON.stringify({
          lpa_document_id: lpaDocId,
          applicant_role: selectedRole,
          attorney_id: attorneyId
        })
      });

      const registeringName = currentDisplayApplicant?.name || donorRecord?.name || "Donor";

      let receivingName = "Donor";
      if (selectedRecipientType === "donor") receivingName = donorRecord?.name || "Donor";
      else if (selectedRecipientType === "attorney") receivingName = attorneyRecords.find(a => a.id === selectedRecipientId)?.name || "Attorney";
      else if (selectedRecipientType === "other") receivingName = otherPeople.find(p => p.id === selectedRecipientId)?.name || "Other";

      updateData({
        registeringPerson: registeringName,
        receivingPerson: receivingName,
        selectedRole,
        selectedAttorneyId,
        selectedRecipientType,
        selectedRecipientId
      });

      onNext();
    } catch (err) {
      console.error("Error saving applicant:", err);
      setError("Failed to save selection.");
    } finally {
      setIsSubmitting(false);
    }
  };

  if (loading) return <div className="flex justify-center p-10"><CircularProgress /></div>;
  if (error) return <Alert severity="error" className="m-4">{error}</Alert>;

  const currentDisplayApplicant = selectedRole === "donor"
    ? donorRecord
    : attorneyRecords.find(a => a.id === selectedAttorneyId);

  return (
    <main className="grow flex items-center justify-center pb-20">
      <div className="max-w-3xl w-full">
        {currentView === "applying" ? (
          <>
            <h4 className={styles.stepHeading}>
              Who is applying <span className="text-cyan-400">to register?</span>
            </h4>

            <div className={styles.dividerZenco}></div>

            <p className={styles.pZenco + " font-normal text-gray-600 mb-8"}>
              This document can't be used until it is registered by the Office of the Public Guardian (OPG).
              Only the donor ({donorRecord?.name}) or one of the attorneys can apply to register this document.
              Select from the option below whether the donor ({donorRecord?.name}) is registering or one of the attorneys.
            </p>

            <div className="mt-6">
              <label className="font-semibold text-sm block mb-2">
                Who is applying to register?
              </label>

              <select
                value={selectedRole}
                onChange={(e) => {
                  setSelectedRole(e.target.value as "donor" | "attorney");
                  setIsChecked(true);
                }}
                className={styles.applicantDropdown}
              >
                <option value="donor">Donor</option>
                <option value="attorney">Attorneys</option>
              </select>
            </div>

            {selectedRole === "attorney" && attorneyRecords.length === 1 && (
              <p className="text-sm text-gray-500 mt-4 mb-2">
                You only have one attorney, they have been automatically selected.
              </p>
            )}

            {selectedRole === "attorney" && attorneyRecords.length > 1 && (
              <div className="mt-4">
                <label className="font-semibold text-sm block mb-2">
                  Select which attorney is applying:
                </label>
                <select
                  value={selectedAttorneyId}
                  onChange={(e) => setSelectedAttorneyId(e.target.value)}
                  className={styles.applicantDropdown}
                >
                  {attorneyRecords.map(a => (
                    <option key={a.id} value={a.id}>{a.name}</option>
                  ))}
                </select>
              </div>
            )}

            {currentDisplayApplicant && (
              <div
                className={`${styles.selectedApplication} ${isChecked ? 'border-2 border-blue-500' : ''} mt-6 cursor-pointer rounded`}
                onClick={() => {
                  if (selectedRole !== "donor") setIsChecked(!isChecked);
                }}
              >
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 bg-gray-300 rounded-full flex items-center justify-center">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-white" viewBox="0 0 20 20" fill="currentColor">
                      <path fillRule="evenodd" d="M10 9a3 3 0 100-6 3 3 0 000 6zm-7 9a7 7 0 1114 0H3z" clipRule="evenodd" />
                    </svg>
                  </div>
                  <div>
                    <p className="font-semibold">{currentDisplayApplicant.name}</p>
                    <p className="text-sm opacity-90">
                      {currentDisplayApplicant.email || "No email provided"}
                    </p>
                  </div>
                </div>

                <input
                  type="checkbox"
                  checked={selectedRole === "donor" ? true : isChecked}
                  disabled={selectedRole === "donor"}
                  onChange={() => {
                    if (selectedRole !== "donor") setIsChecked(!isChecked);
                  }}
                  onClick={(e) => e.stopPropagation()}
                  className="w-5 h-5 accent-blue-500 shrink-0"
                />
              </div>
            )}

            {selectedRole === "attorney" && attorneyRecords.length === 0 && (
              <Alert severity="warning" className="mt-4">
                No primary attorneys found. Please go back to Step 4 and add at least one primary attorney if you wish to select an attorney as the applicant.
              </Alert>
            )}
          </>
        ) : (
          <>
            <h4 className={styles.stepHeading}>
              Who should <span className="text-cyan-400">receive the document?</span>
            </h4>

            <div className={styles.dividerZenco}></div>

            <p className={styles.pZenco + " font-normal text-gray-600"}>
              Once this document is registered with the Office of the Public Guardian (OPG) it will be sent to the person listed below.
            </p>

            <div className="mt-6">
              <label className="font-semibold text-sm block mb-2">
                Where should the registered document be sent?
              </label>

              <select
                value={selectedRecipientType}
                onChange={(e) => {
                  setSelectedRecipientType(e.target.value);
                  setSelectedRecipientId("");
                  if (e.target.value === "donor") setSelectedRecipientId(donorRecord?.id || "");
                  if (e.target.value === "attorney" && attorneyRecords.length === 1) setSelectedRecipientId(attorneyRecords[0].id);
                }}
                className={styles.applicantDropdown}
              >
                <option value="">Choose from this list...</option>
                <option value="attorney">Attorney</option>
                <option value="donor">Donor</option>
                <option value="other">Other</option>
              </select>
            </div>

            <div className="mt-8 space-y-4">
              {selectedRecipientId && (
                <p className="text-sm font-semibold text-gray-500 mb-2">
                  Who you would like to recieve the registered document.
                </p>
              )}
              {selectedRecipientType === "donor" && donorRecord && (
                <div
                  className={`rounded p-4 flex justify-between items-center cursor-pointer transition-all ${selectedRecipientId === donorRecord.id ? 'bg-[#3A4C5F] text-white' : 'border border-gray-200 text-gray-700'}`}
                  onClick={() => setSelectedRecipientId(donorRecord.id)}
                >
                  <div className="flex items-center gap-4">
                    <div className={`w-12 h-12 rounded-full flex items-center justify-center ${selectedRecipientId === donorRecord.id ? 'bg-gray-400' : 'bg-gray-100'}`}>
                      <svg xmlns="http://www.w3.org/2000/svg" className={`h-6 w-6 ${selectedRecipientId === donorRecord.id ? 'text-white' : 'text-gray-400'}`} viewBox="0 0 20 20" fill="currentColor">
                        <path fillRule="evenodd" d="M10 9a3 3 0 100-6 3 3 0 000 6zm-7 9a7 7 0 1114 0H3z" clipRule="evenodd" />
                      </svg>
                    </div>
                    <div>
                      <p className="font-semibold text-lg">{donorRecord.name}</p>
                      <p className={`${selectedRecipientId === donorRecord.id ? 'text-gray-300' : 'text-gray-500'}`}>{donorRecord.email}</p>
                      <button className={`text-sm font-medium hover:underline flex items-center gap-1 mt-1 ${selectedRecipientId === donorRecord.id ? 'text-cyan-300' : 'text-cyan-500'}`}>
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                          <path d="M13.586 3.586a2 2 0 112.828 2.828l-.793.793-2.828-2.828.793-.793zM11.379 5.793L3 14.172V17h2.828l8.38-8.379-2.83-2.828z" />
                        </svg>
                        Update this person's details
                      </button>
                    </div>
                  </div>
                  <input type="checkbox" checked={selectedRecipientId === donorRecord.id} readOnly className="w-6 h-6 accent-white" />
                </div>
              )}

              {selectedRecipientType === "attorney" && attorneyRecords.map(person => (
                <div
                  key={person.id}
                  className={`rounded p-4 flex justify-between items-center cursor-pointer transition-all ${selectedRecipientId === person.id ? 'bg-[#3A4C5F] text-white' : 'border border-gray-200 text-gray-700'}`}
                  onClick={() => setSelectedRecipientId(person.id)}
                >
                  <div className="flex items-center gap-4">
                    <div className={`w-12 h-12 rounded-full flex items-center justify-center ${selectedRecipientId === person.id ? 'bg-gray-400' : 'bg-gray-100'}`}>
                      <svg xmlns="http://www.w3.org/2000/svg" className={`h-6 w-6 ${selectedRecipientId === person.id ? 'text-white' : 'text-gray-400'}`} viewBox="0 0 20 20" fill="currentColor">
                        <path fillRule="evenodd" d="M10 9a3 3 0 100-6 3 3 0 000 6zm-7 9a7 7 0 1114 0H3z" clipRule="evenodd" />
                      </svg>
                    </div>
                    <div>
                      <p className="font-semibold text-lg">{person.name}</p>
                      <p className={`${selectedRecipientId === person.id ? 'text-gray-300' : 'text-gray-500'}`}>{person.email}</p>
                      <button className={`text-sm font-medium hover:underline flex items-center gap-1 mt-1 ${selectedRecipientId === person.id ? 'text-cyan-300' : 'text-cyan-500'}`}>
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                          <path d="M13.586 3.586a2 2 0 112.828 2.828l-.793.793-2.828-2.828.793-.793zM11.379 5.793L3 14.172V17h2.828l8.38-8.379-2.83-2.828z" />
                        </svg>
                        Update this person's details
                      </button>
                    </div>
                  </div>
                  <input
                    type="checkbox"
                    checked={selectedRecipientId === person.id}
                    readOnly
                    className="w-6 h-6 accent-white"
                  />
                </div>
              ))}

              {selectedRecipientType === "other" && otherPeople.map(person => (
                <div
                  key={person.id}
                  className={`rounded p-4 flex justify-between items-center cursor-pointer transition-all ${selectedRecipientId === person.id ? 'bg-[#3A4C5F] text-white' : 'border border-gray-200 text-gray-700'}`}
                  onClick={() => setSelectedRecipientId(person.id)}
                >
                  <div className="flex items-center gap-4">
                    <div className={`w-12 h-12 rounded-full flex items-center justify-center ${selectedRecipientId === person.id ? 'bg-gray-400' : 'bg-gray-100'}`}>
                      <svg xmlns="http://www.w3.org/2000/svg" className={`h-6 w-6 ${selectedRecipientId === person.id ? 'text-white' : 'text-gray-400'}`} viewBox="0 0 20 20" fill="currentColor">
                        <path fillRule="evenodd" d="M10 9a3 3 0 100-6 3 3 0 000 6zm-7 9a7 7 0 1114 0H3z" clipRule="evenodd" />
                      </svg>
                    </div>
                    <div>
                      <p className="font-semibold text-lg">{person.name}</p>
                      <p className={`${selectedRecipientId === person.id ? 'text-gray-300' : 'text-gray-500'}`}>{person.email}</p>
                      <button className={`text-sm font-medium hover:underline flex items-center gap-1 mt-1 ${selectedRecipientId === person.id ? 'text-cyan-300' : 'text-cyan-500'}`}>
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                          <path d="M13.586 3.586a2 2 0 112.828 2.828l-.793.793-2.828-2.828.793-.793zM11.379 5.793L3 14.172V17h2.828l8.38-8.379-2.83-2.828z" />
                        </svg>
                        Update this person's details
                      </button>
                    </div>
                  </div>
                  <input
                    type="checkbox"
                    checked={selectedRecipientId === person.id}
                    readOnly
                    className="w-6 h-6 accent-white"
                  />
                </div>
              ))}
            </div>
          </>
        )}

        <div className="flex items-center justify-between mt-12 mb-10">
          <button
            onClick={() => currentView === "receiving" ? setCurrentView("applying") : null}
            className="flex items-center gap-2 text-gray-400 font-semibold hover:text-gray-600 transition-colors"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
              <path fillRule="evenodd" d="M9.707 16.707a1 1 0 01-1.414 0l-6-6a1 1 0 010-1.414l6-6a1 1 0 011.414 1.414L5.414 9H17a1 1 0 110 2H5.414l4.293 4.293a1 1 0 010 1.414z" clipRule="evenodd" />
            </svg>
            <span>Back</span>
          </button>

          <button
            onClick={handleSave}
            disabled={isSubmitting}
            className={`px-10 py-3 rounded text-white font-bold shadow-lg transition-all flex items-center justify-center min-w-[180px] ${currentView === "applying"
              ? "bg-[#2563eb] hover:bg-blue-700"
              : "bg-[#06b6d4] hover:bg-cyan-600"
              }`}
          >
            {isSubmitting ? <CircularProgress size={24} color="inherit" /> : "Save and continue"}
          </button>
        </div>
      </div>
    </main>
  );
}

"use client";

import { useEffect } from "react";

type Props = {
  data: any;
  updateData: (data: any) => void;
  onNext: () => void;
  isSaving: boolean;
  allFormData: any;
  currentDonorIndex: number;
};

import {
  Alert,
  Box,
  Button,
  CircularProgress,
  Dialog,
  DialogActions,
  DialogContent,
  DialogTitle,
  FormControl,
  FormControlLabel,
  MenuItem,
  Radio,
  RadioGroup,
  Select,
  TextField,
} from "@mui/material";
import { useState } from "react";
import { supabase } from "@/lib/supabase";

type Person = {
  id?: string;
  title: string;
  firstName: string;
  lastName: string;
  middleName: string;
  postcode: string;
  addressLine1: string;
  addressLine2: string;
  city: string;
  county: string;
};

export default function CertificateProviderTab({ data, updateData, onNext, isSaving, allFormData, currentDonorIndex }: Props) {
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [activeLpaId, setActiveLpaId] = useState<string | null>(null);

  const applicationId = allFormData?.who?.applicationId;

  useEffect(() => {
    const init = async () => {
      if (!applicationId) {
        setLoading(false);
        return;
      }

      try {
        const { data: { session } } = await supabase.auth.getSession();
        if (!session) return;
        const token = session.access_token;

        const donorsRes = await fetch(`/api/donors?applicationId=${applicationId}`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        const { data: fetchedDonors } = await donorsRes.json();

        let activeDonorId = allFormData?.["which-donor"]?.donorId;
        if (fetchedDonors) {
          const step1Selection = allFormData?.who?.selection;
          const step1SelectedIds = allFormData?.who?.selectedPeopleIds || [];
          const isLeadSelected =
            step1Selection === "You" ||
            step1Selection === "You and your partner" ||
            step1Selection === "You and someone else";

          const activeDonors = fetchedDonors.filter((d: any) => {
            if (d.is_lead) return isLeadSelected;
            return step1SelectedIds.includes(d.id);
          });
          activeDonorId = activeDonors[currentDonorIndex]?.id;
        }

        if (!activeDonorId) {
          setLoading(false);
          return;
        }

        const lpaDocsRes = await fetch(`/api/lpa-documents?donorId=${activeDonorId}`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        const { data: lpaDocs } = await lpaDocsRes.json();

        if (lpaDocs && lpaDocs.length > 0) {
          const lpaId = lpaDocs[0].id;
          setActiveLpaId(lpaId);

          // 2. Get existing Cert Provider
          const cpRes = await fetch(`/api/certificate-providers?lpaDocId=${lpaId}`, {
            headers: { Authorization: `Bearer ${token}` },
          });
          const { data: cpData } = await cpRes.json();

          if (cpData) {
            setChoice("yes");
            setRelationship(cpData.certification_basis === 'personal_knowledge' ? 'Friend' : (cpData.professional_title || "GP")); // Fallback/default logic

            // Map DB fields to local Person type
            const person: Person & { id: string } = {
              id: cpData.id,
              title: cpData.title || "",
              firstName: cpData.first_name || "",
              lastName: cpData.last_name || "",
              middleName: cpData.middle_name || "",
              postcode: cpData.postcode || "",
              addressLine1: cpData.address_line_1 || "",
              addressLine2: cpData.address_line_2 || "",
              city: cpData.city || "",
              county: cpData.county || "",
            };

            setProviders([person]);
            setSelectedProviderId(person.id);
          }
          else if (data?.hasProvider !== undefined) {
            setChoice(data.hasProvider ? "yes" : "no");
          }
        }
      } catch (err) {
        console.error("Error loading Step 8:", err);
        setError("Failed to load certificate provider details.");
      } finally {
        setLoading(false);
      }
    };

    init();
  }, [allFormData?.who, currentDonorIndex, applicationId]);

  useEffect(() => {
    if (isSaving) {
      handleFinalSave();
    }
  }, [isSaving]);
  const [openModal, setOpenModal] = useState(false);
  const [choice, setChoice] = useState<"yes" | "no" | null>(null);
  const [selectedProviderId, setSelectedProviderId] = useState<string | null>(null);
  const [relationship, setRelationship] = useState<string>("");
  const [providers, setProviders] = useState<(Person & { id: string })[]>([]);

  const [newPerson, setNewPerson] = useState<Person>({
    title: "",
    firstName: "",
    lastName: "",
    middleName: "",
    postcode: "",
    addressLine1: "",
    addressLine2: "",
    city: "",
    county: "",
  });
  const [showManualAddress, setShowManualAddress] = useState(false);

  const handleAddPerson = () => {
    if (
      !newPerson.title ||
      !newPerson.firstName ||
      !newPerson.lastName ||
      !newPerson.postcode ||
      !newPerson.addressLine1 ||
      !newPerson.city
    )
      return;

    // Use a temp ID if not already present
    const personWithId = { ...newPerson, id: providers[0]?.id || `temp-${Date.now()}` };
    setProviders([personWithId]);
    setSelectedProviderId(personWithId.id);

    setNewPerson({
      title: "",
      firstName: "",
      lastName: "",
      middleName: "",
      postcode: "",
      addressLine1: "",
      addressLine2: "",
      city: "",
      county: "",
    });
    setOpenModal(false);
    setShowManualAddress(false);
  };

  const handleFinalSave = async () => {
    if (choice === "yes" && providers.length === 0) {
      setError("Please add certificate provider details.");
      return;
    }
    if (choice === "yes" && !relationship) {
      setError("Please select a relationship.");
      return;
    }

    setIsSubmitting(true);
    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) return;
      const token = session.access_token;

      if (choice === "yes" && providers.length > 0 && activeLpaId) {
        const p = providers[0];
        const isProfessional = ['GP', 'Social Worker', 'Registered Nurse'].includes(relationship);

        const body = {
          lpa_document_id: activeLpaId,
          title: p.title,
          first_name: p.firstName,
          last_name: p.lastName,
          middle_name: p.middleName,
          address_line_1: p.addressLine1,
          address_line_2: p.addressLine2,
          city: p.city,
          county: p.county,
          postcode: p.postcode,
          certification_basis: isProfessional ? 'professional' : 'personal_knowledge',
          professional_title: isProfessional ? relationship : null,
          relationship_length_years: isProfessional ? null : 2
        };

        if (p.id && !p.id.startsWith('temp-')) {
          await fetch("/api/certificate-providers", {
            method: "PATCH",
            headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` },
            body: JSON.stringify({ id: p.id, ...body }),
          });
        } else {
          await fetch("/api/certificate-providers", {
            method: "POST",
            headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` },
            body: JSON.stringify(body),
          });
        }
      }

      updateData({ hasProvider: choice === "yes", relationship });
      onNext();
    } catch (err) {
      console.error("Error saving certificate provider:", err);
      setError("Failed to save. Please try again.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const allowedRelationships = [
    { label: "Friend", value: "Friend" },
    { label: "Neighbour", value: "Neighbour" },
    { label: "GP", value: "GP" },
    { label: "Social Worker", value: "Social Worker" },
    { label: "Registered Nurse", value: "Registered Nurse" },
  ];

  const disallowedRelationships = [
    { label: "Partner -- (this person can't be used)", value: "Partner" },
    { label: "Son -- (this person can't be used)", value: "Son" },
    { label: "Daughter -- (this person can't be used)", value: "Daughter" },
    { label: "Brother -- (this person can't be used)", value: "Brother" },
    { label: "Sister -- (this person can't be used)", value: "Sister" },
    { label: "Father -- (this person can't be used)", value: "Father" },
    { label: "Mother -- (this person can't be used)", value: "Mother" },
    { label: "Father-in-law -- (this person can't be used)", value: "Father-in-law" },
    { label: "Mother-in-law -- (this person can't be used)", value: "Mother-in-law" },
  ];

  if (loading) return <Box p={10} display="flex" justifyContent="center"><CircularProgress /></Box>;

  return (
    <>
      <section className="max-w-3xl mx-auto pb-10">
        {error && <Alert severity="error" className="mb-6">{error}</Alert>}
        <div className="flex flex-col gap-7">
          <div className="flex flex-col gap-9">
            <h4 className="text-center text-3xl font-bold text-[#334a5e]">
              The <span className="text-cyan-400">Certificate Provider</span>
            </h4>

            <div className="h-0.5 w-full bg-gradient-to-r from-transparent via-cyan-400 to-transparent"></div>

            <div className="flex flex-col gap-5">
              <p className="text-gray-700 font-medium">
                This person signs to confirm they have discussed the Lasting
                Power of Attorney with the Donor and that they are fully aware
                of what they are doing.
              </p>

              <div className="flex flex-col gap-4">
                <p className="text-xl font-semibold">
                  Do you want to choose your certificate provider now?
                </p>
                <div className="flex flex-col gap-0 border-2 border-[#334a5e] rounded-md overflow-hidden">
                  <button
                    onClick={() => setChoice("no")}
                    className={`leading-loose p-4 text-center font-semibold transition-colors ${choice === "no"
                      ? "bg-[#334a5e] text-white"
                      : "bg-white text-[#334a5e] hover:bg-gray-50"
                      }`}
                  >
                    No, I will add them when I sign the documents
                  </button>
                  <button
                    onClick={() => setChoice("yes")}
                    className={`leading-loose p-4 text-center font-semibold border-t-2 border-[#334a5e] transition-colors ${choice === "yes"
                      ? "bg-[#334a5e] text-white"
                      : "bg-white text-[#334a5e] hover:bg-gray-50"
                      }`}
                  >
                    Yes, I know the details now
                  </button>
                </div>
              </div>

              {choice === "yes" && (
                <div className="flex flex-col gap-6 animate-fadeIn">
                  <div className="flex flex-col gap-5 bg-cyan-50 rounded p-6 border border-cyan-200">
                    <div className="flex text-xl text-cyan-900 font-semibold items-center gap-3">
                      <svg
                        xmlns="http://www.w3.org/2000/svg"
                        viewBox="0 0 24 24"
                        width="24"
                        height="24"
                        className="text-cyan-500"
                        fill="currentColor"
                      >
                        <path d="M12 22C6.47715 22 2 17.5228 2 12C2 6.47715 6.47715 2 12 2C17.5228 2 22 6.47715 22 12C22 17.5228 17.5228 22 12 22ZM12 9.5C12.8284 9.5 13.5 8.82843 13.5 8C13.5 7.17157 12.8284 6.5 12 6.5C11.1716 6.5 10.5 7.17157 10.5 8C10.5 8.82843 11.1716 9.5 12 9.5ZM14 15H13V10.5H10V12.5H11V15H10V17H14V15Z"></path>
                      </svg>
                      <p>Please read the below carefully</p>
                    </div>
                    <div className="flex flex-col gap-4 text-cyan-800 text-sm">
                      <p className="text-lg font-bold">Recommended</p>
                      <div className="space-y-3 leading-relaxed">
                        <p>We suggest using a friend or neighbour of the donor to be a certificate provider.</p>
                        <p>This person signs to confirm they have discussed the Lasting Power of Attorney with the Donor.</p>
                        <p>This person must be over 18 and have known the donor for a minimum of 2 years.</p>
                        <p>This is very important: there are rules on who can't be a certificate provider, too.</p>
                        <p>The certificate provider <u className="font-bold">must not</u> be:</p>
                        <ul className="list-disc ps-6 space-y-2">
                          <li>An attorney or replacement attorney</li>
                          <li>A relative, or someone who's related to an attorney - this includes civil partners, spouses, in-laws and step-relatives</li>
                          <li>The Donor's (unmarried) partner, or the partner of one of your attorneys - whether they live together or not</li>
                          <li>The Donor's, or attorney's business partner or employee</li>
                          <li>Someone who owns, manages, is a director of or works at a care home where they live, or anyone related to them</li>
                        </ul>
                      </div>
                      <p className="text-lg font-bold mt-2">Alternative</p>
                      <p>You can also use a medical professional (doctor, social worker, nurse) to sign the document. They will sign in their professional capacity to ensure the donor has mental capacity.</p>
                    </div>
                  </div>

                  <div className="flex flex-col gap-4">
                    <p className="text-lg font-semibold">Please add the certificate provider details below.</p>

                    {providers.map((p: any) => (
                      <div key={p.id} className="bg-[#3A4C5F] text-white rounded p-6 flex justify-between items-center ring-2 ring-blue-500">
                        <div className="flex items-center gap-4">
                          <div className="w-12 h-12 bg-gray-400 rounded-full flex items-center justify-center">
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" viewBox="0 0 20 20" fill="currentColor">
                              <path fillRule="evenodd" d="M10 9a3 3 0 100-6 3 3 0 000 6zm-7 9a7 7 0 1114 0H3z" clipRule="evenodd" />
                            </svg>
                          </div>
                          <div>
                            <p className="font-bold text-lg">{p.firstName} {p.lastName}</p>
                            <p className="text-gray-300 text-sm">{p.email || "No email provided"}</p>
                            <button
                              onClick={() => setOpenModal(true)}
                              className="text-cyan-300 text-sm font-medium hover:underline flex items-center gap-1 mt-1"
                            >
                              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                                <path d="M13.586 3.586a2 2 0 112.828 2.828l-.793.793-2.828-2.828.793-.793zM11.379 5.793L3 14.172V17h2.828l8.38-8.379-2.83-2.828z" />
                              </svg>
                              Change this person
                            </button>
                          </div>
                        </div>
                        <input type="checkbox" checked className="w-6 h-6 accent-white" readOnly />
                      </div>
                    ))}

                    {providers.length === 0 && (
                      <button
                        onClick={() => setOpenModal(true)}
                        className="border-2 border-dashed border-gray-300 p-4 flex items-center justify-center gap-2 font-semibold text-gray-600 hover:border-cyan-400 hover:text-cyan-500 transition-all cursor-pointer rounded"
                      >
                        <svg
                          xmlns="http://www.w3.org/2000/svg"
                          viewBox="0 0 24 24"
                          width="20"
                          height="20"
                          fill="currentColor"
                        >
                          <path d="M14 14.252V22H4C4 17.5817 7.58172 14 12 14C12.6906 14 13.3608 14.0875 14 14.252ZM12 13C8.685 13 6 10.315 6 7C6 3.685 8.685 1 12 1C15.315 1 18 3.685 18 7C18 10.315 15.315 13 12 13ZM18 17V14H20V17H23V19H20V22H18V19H15V17H18Z" />
                        </svg>
                        <span>Add a Certificate Provider</span>
                      </button>
                    )}
                  </div>

                  {providers.length > 0 && (
                    <div className="flex flex-col gap-3 animate-fadeIn">
                      <p className="text-lg font-semibold">What relationship is this person to the Donor?</p>
                      <Select
                        value={relationship}
                        onChange={(e) => setRelationship(e.target.value)}
                        fullWidth
                        displayEmpty
                        className="bg-white border-2 border-gray-300 rounded-md outline-none"
                        renderValue={(selected) => {
                          if (!selected) return <span className="text-gray-400">Choose Relationship...</span>;
                          const all = [...allowedRelationships, ...disallowedRelationships];
                          const match = all.find(r => r.value === selected);
                          return <span className="flex items-center gap-2">
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 text-green-500" viewBox="0 0 20 20" fill="currentColor">
                              <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                            </svg>
                            {match?.label || selected}
                          </span>;
                        }}
                      >
                        <MenuItem disabled value="" className="bg-[#2563eb] text-white font-bold opacity-100 italic">
                          Choose Relationship...
                        </MenuItem>
                        {allowedRelationships.map((r) => (
                          <MenuItem key={r.value} value={r.value} className="flex gap-2 items-center">
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 text-green-500" viewBox="0 0 20 20" fill="currentColor">
                              <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                            </svg>
                            {r.label}
                          </MenuItem>
                        ))}
                        {disallowedRelationships.map((r) => (
                          <MenuItem key={r.value} value={r.value} disabled className="flex gap-2 items-center bg-gray-100 text-gray-500 opacity-60">
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 text-red-500" viewBox="0 0 20 20" fill="currentColor">
                              <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                            </svg>
                            {r.label}
                          </MenuItem>
                        ))}
                      </Select>
                    </div>
                  )}
                </div>
              )}
            </div>
          </div>

          <div className="flex items-center justify-between mt-12 mb-10">
            <button
              onClick={() => { }}
              className="flex items-center gap-2 text-gray-400 font-semibold hover:text-gray-600 transition-colors"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M9.707 16.707a1 1 0 01-1.414 0l-6-6a1 1 0 010-1.414l6-6a1 1 0 011.414 1.414L5.414 9H17a1 1 0 110 2H5.414l4.293 4.293a1 1 0 010 1.414z" clipRule="evenodd" />
              </svg>
              <span>Back</span>
            </button>

            <button
              onClick={handleFinalSave}
              disabled={isSubmitting}
              className="px-10 py-3 rounded text-white font-bold shadow-lg transition-all flex items-center justify-center min-w-[180px] bg-[#06b6d4] hover:bg-cyan-600 disabled:bg-gray-400"
            >
              {isSubmitting ? <CircularProgress size={24} color="inherit" /> : "Save and continue"}
            </button>
          </div>
        </div>
      </section>

      <Dialog open={openModal} onClose={() => setOpenModal(false)} maxWidth="sm" fullWidth>
        <div className="flex justify-between items-center px-6 py-4 bg-[#334a5e]">
          <DialogTitle className="text-white p-0">Add person</DialogTitle>
          <button
            className="text-white hover:text-gray-300 transition-colors"
            onClick={() => setOpenModal(false)}
          >
            <svg
              xmlns="http://www.w3.org/2000/svg"
              viewBox="0 0 24 24"
              width="24"
              height="24"
              fill="currentColor"
            >
              <path d="M11.9997 10.5865L16.9495 5.63672L18.3637 7.05093L13.4139 12.0007L18.3637 16.9504L16.9495 18.3646L11.9997 13.4149L7.04996 18.3646L5.63574 16.9504L10.5855 12.0007L5.63574 7.05093L7.04996 5.63672L11.9997 10.5865Z"></path>
            </svg>
          </button>
        </div>

        <DialogContent className="p-8 space-y-8">
          <div className="space-y-6">
            <p className="text-xl font-bold text-[#334a5e]">Full legal name</p>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <FormControl fullWidth>
                <p className="text-sm font-semibold mb-2 text-gray-600">Title</p>
                <Select
                  value={newPerson.title}
                  onChange={(e) =>
                    setNewPerson({ ...newPerson, title: e.target.value })
                  }
                  className="bg-white"
                >
                  {["Mr", "Mrs", "Miss", "Ms", "Mx", "Dr", "Rev", "Prof", "Lady", "Lord"].map((title) => (
                    <MenuItem key={title} value={title}>{title}</MenuItem>
                  ))}
                </Select>
              </FormControl>

              <div className="hidden md:block"></div>

              <FormControl fullWidth>
                <p className="text-sm font-semibold mb-2 text-gray-600">First Name</p>
                <TextField
                  fullWidth
                  value={newPerson.firstName}
                  onChange={(e) =>
                    setNewPerson({ ...newPerson, firstName: e.target.value })
                  }
                  variant="outlined"
                />
              </FormControl>

              <FormControl fullWidth>
                <p className="text-sm font-semibold mb-2 text-gray-600">Last Name</p>
                <TextField
                  fullWidth
                  value={newPerson.lastName}
                  onChange={(e) =>
                    setNewPerson({ ...newPerson, lastName: e.target.value })
                  }
                  variant="outlined"
                />
              </FormControl>
            </div>

            <FormControl fullWidth>
              <p className="text-sm font-semibold mb-2 text-gray-600">Middle Name (optional)</p>
              <TextField
                fullWidth
                value={newPerson.middleName}
                onChange={(e) =>
                  setNewPerson({ ...newPerson, middleName: e.target.value })
                }
                variant="outlined"
              />
            </FormControl>
          </div>

          <div className="space-y-6">
            <p className="text-xl font-bold text-[#334a5e]">What's their address?</p>
            <div className="flex gap-4 items-end">
              <FormControl className="flex-grow">
                <p className="text-sm font-semibold mb-2 text-gray-600">Postcode</p>
                <TextField
                  fullWidth
                  value={newPerson.postcode}
                  onChange={(e) =>
                    setNewPerson({ ...newPerson, postcode: e.target.value })
                  }
                  variant="outlined"
                />
              </FormControl>
              <Button
                variant="contained"
                className="bg-blue-500 hover:bg-blue-600 h-[56px] px-8 font-bold"
              >
                Search
              </Button>
            </div>
            {!showManualAddress && (
              <button
                type="button"
                onClick={() => setShowManualAddress(true)}
                className="text-cyan-500 font-semibold hover:underline"
              >
                Enter address manually
              </button>
            )}

            {showManualAddress && (
              <div className="space-y-6 animate-fadeIn">
                <FormControl fullWidth>
                  <p className="text-sm font-semibold mb-2 text-gray-600">Address Line 1</p>
                  <TextField
                    fullWidth
                    value={newPerson.addressLine1}
                    onChange={(e) =>
                      setNewPerson({ ...newPerson, addressLine1: e.target.value })
                    }
                    variant="outlined"
                  />
                </FormControl>

                <FormControl fullWidth>
                  <p className="text-sm font-semibold mb-2 text-gray-600">Address Line 2 (optional)</p>
                  <TextField
                    fullWidth
                    value={newPerson.addressLine2}
                    onChange={(e) =>
                      setNewPerson({ ...newPerson, addressLine2: e.target.value })
                    }
                    variant="outlined"
                  />
                </FormControl>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <FormControl fullWidth>
                    <p className="text-sm font-semibold mb-2 text-gray-600">City</p>
                    <TextField
                      fullWidth
                      value={newPerson.city}
                      onChange={(e) =>
                        setNewPerson({ ...newPerson, city: e.target.value })
                      }
                      variant="outlined"
                    />
                  </FormControl>

                  <FormControl fullWidth>
                    <p className="text-sm font-semibold mb-2 text-gray-600">County (optional)</p>
                    <TextField
                      fullWidth
                      value={newPerson.county}
                      onChange={(e) =>
                        setNewPerson({ ...newPerson, county: e.target.value })
                      }
                      variant="outlined"
                    />
                  </FormControl>
                </div>
              </div>
            )}
          </div>

          <div className="hidden">
            <p className="text-xl font-bold text-[#334a5e]">What's their email address? (optional)</p>
            <TextField
              fullWidth
              value={""}
              variant="outlined"
              placeholder="email@example.com"
            />
          </div>

          <div className="space-y-4">
            <p className="text-xl font-bold text-[#334a5e]">Age</p>
            <RadioGroup
              defaultValue="over18"
              name="age-group"
              className="flex flex-row gap-8"
            >
              <FormControlLabel
                value="over18"
                control={<Radio color="primary" />}
                label={<span className="font-medium">Over 18</span>}
              />
              <FormControlLabel
                disabled
                value="under18"
                control={<Radio color="primary" />}
                label={<span className="font-medium">Under 18 (Cannot be a provider)</span>}
              />
            </RadioGroup>
          </div>
        </DialogContent>

        <DialogActions className="p-6 bg-gray-50 border-t">
          <Button
            variant="contained"
            onClick={handleAddPerson}
            fullWidth
            className="bg-blue-600 hover:bg-blue-700 py-4 text-lg font-bold shadow-lg text-white"
          >
            Save and continue
          </Button>
        </DialogActions>
      </Dialog>
    </>
  );
}

"use client";

import { useState, useEffect } from "react";
import { TextField, Box, CircularProgress, Alert } from "@mui/material";
import { supabase } from "@/lib/supabase";

type Props = {
  data: any;
  updateData: (data: any) => void;
  onNext: () => void;
  isSaving: boolean;
  allFormData: any;
  currentDonorIndex: number;
};

type ViewState =
  | "exemption-check"
  | "benefit-selection"
  | "evidence-exemption"
  | "remission-check" // Combined Income & UC & Types
  | "evidence-remission"
  | "payment";

export default function OPGFeesTab({ data, updateData, onNext, isSaving, allFormData, currentDonorIndex }: Props) {
  const [currentView, setCurrentView] = useState<ViewState>("exemption-check");
  const [remissionStep, setRemissionStep] = useState(1); // 1: Questions, 2: Income Types

  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [hasBenefits, setHasBenefits] = useState<boolean | null>(data?.hasBenefits ?? null);
  const [incomeLess12k, setIncomeLess12k] = useState<boolean | null>(data?.incomeLess12k ?? null);
  const [hasUniversalCredit, setHasUniversalCredit] = useState<boolean | null>(data?.hasUniversalCredit ?? null);

  const [selectedBenefits, setSelectedBenefits] = useState<string[]>(data?.benefits || []);
  const [selectedIncomeTypes, setSelectedIncomeTypes] = useState<string[]>(data?.incomeTypes || []);
  const [paymentMethod, setPaymentMethod] = useState<"Card" | "Cheque" | null>(data?.paymentMethod || null);
  const [phoneNumber, setPhoneNumber] = useState(data?.phoneNumber || "");

  const donorName = allFormData?.["which-donor"]?.firstName && allFormData?.["which-donor"]?.lastName
    ? "You" // Defaulting to "You" as per refined screenshots, but keeping logic for donorName if needed
    : "You";

  const applicationId = allFormData?.who?.applicationId;

  const getDonorId = async () => {
    const { data: { session } } = await supabase.auth.getSession();
    if (!session) return null;
    const token = session.access_token;

    const step1Selection = allFormData?.who?.selection;
    const step1SelectedIds = allFormData?.who?.selectedPeopleIds || [];
    const isLeadSelected =
      step1Selection === "You" ||
      step1Selection === "You and your partner" ||
      step1Selection === "You and someone else";

    const donorsRes = await fetch(`/api/donors?applicationId=${applicationId}`, {
      headers: { Authorization: `Bearer ${token}` },
    });
    const { data: fetchedDonors } = await donorsRes.json();

    const activeDonors = (fetchedDonors || []).filter((d: any) => {
      if (d.is_lead) return isLeadSelected;
      return step1SelectedIds.includes(d.id);
    });

    return activeDonors[currentDonorIndex]?.id;
  };

  useEffect(() => {
    const init = async () => {
      const donorId = await getDonorId();
      if (!donorId) {
        setLoading(false);
        return;
      }

      try {
        const { data: { session } } = await supabase.auth.getSession();
        if (!session) return;
        const token = session.access_token;

        const res = await fetch(`/api/benefits-assessments?donorId=${donorId}`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        const { data: assessment } = await res.json();

        if (assessment) {
          setHasBenefits(assessment.receives_means_tested_benefits);
          setSelectedBenefits(assessment.selected_benefits || []);
          setIncomeLess12k(!assessment.income_12k_or_more);
          setHasUniversalCredit(assessment.receives_universal_credit);
          setSelectedIncomeTypes(assessment.income_sources || []);
        }
      } catch (err) {
        console.error("Error loading Step 9:", err);
      } finally {
        setLoading(false);
      }
    };

    init();
  }, [currentDonorIndex]);

  const handleFinalSave = async () => {
    const donorId = await getDonorId();
    if (!donorId) {
      onNext();
      return;
    }

    setIsSubmitting(true);
    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) return;
      const token = session.access_token;

      const body = {
        donor_id: donorId,
        receives_means_tested_benefits: hasBenefits,
        selected_benefits: selectedBenefits,
        income_12k_or_more: !incomeLess12k,
        receives_universal_credit: hasUniversalCredit,
        income_sources: selectedIncomeTypes,
        calculated_fee_tier: hasBenefits ? 'exempt' : (incomeLess12k || hasUniversalCredit ? 'reduced' : 'full')
      };

      await fetch("/api/benefits-assessments", {
        method: "POST",
        headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` },
        body: JSON.stringify(body),
      });

      updateData({
        ...data,
        benefits: selectedBenefits,
        incomeTypes: selectedIncomeTypes,
        hasBenefits,
        incomeLess12k,
        hasUniversalCredit,
        paymentMethod,
        phoneNumber
      });
      onNext();
    } catch (err) {
      console.error("Error saving Step 9:", err);
      setError("Failed to save. Please try again.");
    } finally {
      setIsSubmitting(false);
    }
  };

  useEffect(() => {
    if (isSaving) {
      handleFinalSave();
    }
  }, [isSaving]);

  const toggleBenefit = (id: string) => {
    setSelectedBenefits(prev => prev.includes(id) ? prev.filter(b => b !== id) : [...prev, id]);
  };

  const toggleIncomeType = (id: string) => {
    setSelectedIncomeTypes(prev => prev.includes(id) ? prev.filter(b => b !== id) : [...prev, id]);
  };

  const benefitsOptions = [
    { id: "income-support", label: "Income Support" },
    { id: "income-based-esa", label: "Income based employment and support allowance" },
    { id: "income-based-jsa", label: "Income Based Jobseeker's Allowance" },
    { id: "pension-credit", label: "Guaranteed Credit Element of State Pension Credit" },
    { id: "housing-benefit", label: "Housing Benefit" },
    { id: "council-tax", label: "Council Tax Reduction/Support" },
    { id: "none", label: "None of above" },
  ];

  const exemptionEvidence: Record<string, { title: string; desc: React.ReactNode }> = {
    "income-support": {
      title: "Income support",
      desc: <>Evidence provided for Income Support is usually provided from the <a href="https://www.gov.uk" className="text-cyan-500 underline">gov.uk website</a> through an online log in for you showing your income support that you receive and will have your <span className="text-cyan-500 font-bold">name</span> and <span className="text-cyan-500 font-bold">address</span> on the print outs.</>
    },
    "income-based-esa": {
      title: "Income based employment and support allowance",
      desc: <>An <span className="text-cyan-500 font-bold">official letter</span> from the <span className="text-cyan-500 font-bold">Department of Work and Pensions</span> for the current financial year.</>
    },
    "income-based-jsa": {
      title: "Income Based Jobseeker's Allowance",
      desc: <>An <span className="text-cyan-500 font-bold">official letter</span> from the <span className="text-cyan-500 font-bold">Department of Work and Pensions</span> for the current financial year.</>
    },
    "pension-credit": {
      title: "Guaranteed Credit Element of State Pension Credit",
      desc: <>An <span className="text-cyan-500 font-bold">official letter</span> from the <span className="text-cyan-500 font-bold">Pension Service</span> for the current financial year. Please contact the HMRC helpline if you need copies on <span className="text-cyan-500 font-bold underline">0800 731 0469</span>.</>
    },
    "housing-benefit": {
      title: "Housing Benefit",
      desc: <>An <span className="text-cyan-500 font-bold">official letter</span> from your <span className="text-cyan-500 font-bold">local Council</span> for the current financial year.</>
    },
    "council-tax": {
      title: "Council Tax Reduction/Support",
      desc: <>An <span className="text-cyan-500 font-bold">offer letter</span> from your <span className="text-cyan-500 font-bold">local Council</span> for the current financial year.</>
    },
    "none": {
      title: "None of above",
      desc: "Please provide any other relevant financial documents if requested."
    }
  };

  const incomeOptions = [
    { id: "paid-employment", label: "Paid employment" },
    { id: "self-employment", label: "Self-employment" },
    { id: "non-means-benefits", label: "Non-means-tested benefits and pensions" },
    { id: "interest", label: "Interest from capital stocks, shares or bonds" },
    { id: "no-income", label: "No income" },
    { id: "none", label: "None of above" },
  ];

  const evidenceData: Record<string, { title: string; desc: React.ReactNode }> = {
    "paid-employment": {
      title: "Paid employment",
      desc: <>A <span className="text-cyan-500 font-bold">P60</span> or <span className="text-cyan-500 font-bold">3 months' consecutive wage slips</span> from your <span className="text-cyan-500 font-bold underline">current employment</span>,(from when returning documents e.g., if returning documents in May you would need to provide April, March & February).</>
    },
    "self-employment": {
      title: "Self-employment",
      desc: <>Your most recent <span className="text-cyan-500 font-bold underline">self-assessment tax return</span> and <span className="text-cyan-500 font-bold underline">HMRC tax calculation</span> or <span className="text-cyan-500 font-bold underline">audited accounts</span> certified by a qualified accountant.</>
    },
    "non-means-benefits": {
      title: "Non-means-tested benefits and pensions",
      desc: <>An <span className="text-cyan-500 font-bold underline">official letter</span> from the <span className="text-cyan-500 font-bold underline text-xs">Pension Service</span> for the current financial year. Please contact the HMRC helpline if you need copies on <span className="text-cyan-500 font-bold underline">0800 731 0469</span>.</>
    },
    "interest": {
      title: "Interest from capital stocks, shares or bonds",
      desc: <><span className="text-cyan-500 font-bold underline">Statements</span> or <span className="text-cyan-500 font-bold underline">vouchers</span> showing <span className="text-cyan-500 font-bold underline">gross income</span> for the current financial year.</>
    },
    "no-income": {
      title: "No income",
      desc: <>Your most recent <span className="text-cyan-500 font-bold underline">self-assessment tax return</span> and <span className="text-cyan-500 font-bold underline">HMRC tax calculation</span> or <span className="text-cyan-500 font-bold underline">audited accounts</span> certified by a qualified accountant.</>
    },
    "none": {
      title: "None of above",
      desc: "Please provide any other relevant financial documents if requested."
    }
  };

  const getFinalAmount = () => {
    if (hasBenefits) return 0;
    if (incomeLess12k || hasUniversalCredit) return 92;
    return 184;
  };

  const finalAmount = getFinalAmount();

  if (loading) return <Box p={10} display="flex" justifyContent="center"><CircularProgress /></Box>;

  return (
    <main className="max-w-4xl mx-auto pb-20 px-4">
      {error && <Alert severity="error" className="mb-6">{error}</Alert>}
      {/* Dynamic Heading */}
      <div className="text-center mb-10">
        <h4 className="text-3xl font-bold text-[#334a5e]">
          Registration {currentView === "payment" ? "fees" : "fee"}{" "}
          <span className="text-cyan-400">
            {currentView === "payment" ? (hasBenefits || incomeLess12k || hasUniversalCredit ? "fees" : "fees") : (hasBenefits === false ? "remission" : "exemption")}
          </span>
        </h4>
        {(currentView === "evidence-exemption" || currentView === "evidence-remission") && (
          <p className="text-cyan-500 font-bold mt-2 uppercase tracking-wide text-lg">Evidence for {hasBenefits ? "exemption" : "remission"}</p>
        )}
        <div className="h-0.5 w-full bg-gradient-to-r from-transparent via-gray-200 to-transparent mt-6"></div>
      </div>

      <div className="space-y-6 text-gray-700 leading-relaxed">
        {/* VIEW 1: EXEMPTION CHECK */}
        {currentView === "exemption-check" && (
          <div className="space-y-6 animate-fadeIn">
            <p>
              If <span className="text-cyan-500 font-bold">{donorName}</span> are in receipt of means tested benefits, you may be eligible to be exempt from paying registration fees with the Office of the Public Guardian.
            </p>
            <p>
              If applicable, please select any benefits below that <span className="text-cyan-500 font-bold">{donorName}</span> are in receipt of.
            </p>
            <p className="font-bold border-l-4 border-cyan-400 pl-4 py-1">
              You must be able to supply evidence for at least one if selected.
            </p>
            <p className="text-xs text-gray-500">
              Please note, if <span className="text-cyan-500 font-bold">{donorName}</span> have been awarded personal injury damages of more than £16,000 which were ignored when they were assessed for one of the qualifying benefits, they won't qualify for exemption.
            </p>

            <div className="pt-6">
              <p className="text-lg font-bold mb-4">Are you in receipt of means tested benefits?</p>
              <div className="flex flex-col border-2 border-[#334a5e] rounded-lg overflow-hidden shadow-sm">
                <button
                  onClick={() => {
                    setHasBenefits(false);
                    setSelectedBenefits([]);
                  }}
                  className={`p-5 text-xl font-semibold transition-all ${hasBenefits === false ? "bg-[#334a5e] text-white" : "bg-white text-gray-700 hover:bg-gray-50"}`}
                >
                  No, you do not receive benefits
                </button>
                <button
                  onClick={() => setHasBenefits(true)}
                  className={`p-5 text-xl font-semibold border-t-2 border-[#334a5e] transition-all ${hasBenefits === true ? "bg-[#334a5e] text-white" : "bg-white text-gray-700 hover:bg-gray-50"}`}
                >
                  Yes, you are in receipt of benefits
                </button>
              </div>
            </div>

            {hasBenefits === true && (
              <div className="pt-8 animate-fadeIn">
                <p className="text-xl font-bold mb-6 text-gray-800">Which benefits do you get?</p>
                <div className="space-y-3">
                  {benefitsOptions.map(opt => (
                    <div
                      key={opt.id}
                      onClick={() => toggleBenefit(opt.id)}
                      className={`flex justify-between items-center p-5 border-2 rounded-xl cursor-pointer transition-all ${selectedBenefits.includes(opt.id) ? "border-[#334a5e] bg-gray-50" : "border-gray-100 hover:border-cyan-200 bg-white"}`}
                    >
                      <p className={`font-black text-lg ${selectedBenefits.includes(opt.id) ? "text-[#334a5e]" : "text-gray-700"}`}>{opt.label}</p>
                      <div className={`w-7 h-7 border-2 rounded flex items-center justify-center ${selectedBenefits.includes(opt.id) ? "bg-[#334a5e] border-[#334a5e]" : "border-gray-300 bg-white"}`}>
                        {selectedBenefits.includes(opt.id) && (
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-white" viewBox="0 0 20 20" fill="currentColor">
                            <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                          </svg>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}

        {/* VIEW 3: EVIDENCE (EXEMPTION) */}
        {currentView === "evidence-exemption" && (
          <div className="space-y-8 animate-fadeIn">
            <div className="space-y-4">
              <p>
                When these documents are sent to the Office of the Public Guardian, you will need to provide one of the following as evidence to prove the donor is eligible for fee exemption.
              </p>
              <div className="bg-orange-50 border-l-4 border-orange-400 p-4 rounded-r-lg shadow-sm">
                <p className="font-bold text-orange-800 leading-tight text-sm">
                  You don't need these to finish your documents today, this is just for information as it is a good idea to get these ready while we post the documents to you.
                </p>
              </div>
            </div>

            <div className="space-y-4">
              {selectedBenefits.map(id => {
                const evidence = exemptionEvidence[id];
                if (!evidence) return null;
                return (
                  <div key={id} className="p-6 border-2 border-gray-100 rounded-xl shadow-sm bg-white hover:border-cyan-200 transition-all">
                    <p className="text-lg font-bold text-gray-400 mb-2 uppercase tracking-wide">
                      {evidence.title}
                    </p>
                    <p className="text-gray-600 leading-relaxed text-sm font-medium">
                      {evidence.desc}
                    </p>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {/* VIEW 4: REMISSION CHECK (COMBINED) */}
        {currentView === "remission-check" && (
          <div className="space-y-6 animate-fadeIn text-gray-700">
            <p>
              If <span className="text-cyan-500 font-bold">{donorName}</span> are not in receipt of benefits which qualify for exemption of the fees, but the gross annual income is less than £12,000 per year (before tax) or you receive Universal Credit, you may be able to receive a fee remission of 50% discount on the registration fees with the Office of the Public Guardian.
            </p>
            <p>
              If applicable, please select any of the requirements below that <span className="text-cyan-500 font-bold">{donorName}</span> meet.
            </p>
            <p className="font-bold border-l-4 border-cyan-400 pl-4 py-1">
              You must be able to supply evidence for at least one if selected.
            </p>

            <div className="pt-6">
              <p className="text-lg font-bold mb-4">Is your income less than £12,000 a year?</p>
              <div className="flex flex-col border-2 border-[#334a5e] rounded-lg overflow-hidden shadow-sm mb-8">
                <button
                  onClick={() => {
                    setIncomeLess12k(false);
                    setSelectedIncomeTypes([]);
                  }}
                  className={`p-5 text-xl font-semibold transition-all ${incomeLess12k === false ? "bg-[#334a5e] text-white" : "bg-white text-gray-700 hover:bg-gray-50"}`}
                >
                  No, your income is £12k per year or more
                </button>
                <button
                  onClick={() => {
                    setIncomeLess12k(true);
                  }}
                  className={`p-5 text-xl font-semibold border-t-2 border-[#334a5e] transition-all ${incomeLess12k === true ? "bg-[#334a5e] text-white" : "bg-white text-gray-700 hover:bg-gray-50"}`}
                >
                  Yes, your income is less than £12k per year
                </button>
              </div>

              {remissionStep === 1 && (
                <div className="animate-fadeIn">
                  <p className="text-lg font-bold mb-4">Do you receive Universal Credit?</p>
                  <div className="flex flex-col border-2 border-[#334a5e] rounded-lg overflow-hidden shadow-sm">
                    <button
                      onClick={() => setHasUniversalCredit(false)}
                      className={`p-5 text-xl font-semibold transition-all ${hasUniversalCredit === false ? "bg-[#334a5e] text-white" : "bg-white text-gray-700 hover:bg-gray-50"}`}
                    >
                      No, you do not receive universal credit
                    </button>
                    <button
                      onClick={() => setHasUniversalCredit(true)}
                      className={`p-5 text-xl font-semibold border-t-2 border-[#334a5e] transition-all ${hasUniversalCredit === true ? "bg-[#334a5e] text-white" : "bg-white text-gray-700 hover:bg-gray-50"}`}
                    >
                      Yes, you do receive universal credit
                    </button>
                  </div>
                </div>
              )}

              {remissionStep === 2 && (
                <div className="space-y-6 animate-fadeIn mb-8">
                  <p className="text-lg font-bold uppercase tracking-tight text-gray-800">Please choose anything below that applies to you.</p>
                  <p className="text-gray-500 font-semibold mb-4">Select from the choices below:</p>
                  <div className="space-y-3">
                    {incomeOptions.map(opt => (
                      <div
                        key={opt.id}
                        onClick={() => toggleIncomeType(opt.id)}
                        className={`flex justify-between items-center p-5 border rounded-lg cursor-pointer transition-all ${selectedIncomeTypes.includes(opt.id) ? "border-[#334a5e] bg-[#334a5e] text-white shadow-md" : "border-gray-300 hover:border-cyan-400"}`}
                      >
                        <p className={`font-black text-lg ${selectedIncomeTypes.includes(opt.id) ? "text-white" : "text-gray-700"}`}>{opt.label}</p>
                        <div className={`w-7 h-7 border-2 rounded flex items-center justify-center ${selectedIncomeTypes.includes(opt.id) ? "bg-white border-white" : "border-gray-400 bg-white"}`}>
                          {selectedIncomeTypes.includes(opt.id) && (
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-[#334a5e]" viewBox="0 0 20 20" fill="currentColor">
                              <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                            </svg>
                          )}
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>
        )}

        {/* VIEW 6: EVIDENCE FOR REMISSION */}
        {currentView === "evidence-remission" && (
          <div className="space-y-8 animate-fadeIn">
            <div className="space-y-4">
              <p>
                When these documents are sent to the Office of the Public Guardian, you will need to provide one of the following as evidence to prove the donor is eligible for fee remission.
              </p>
              <div className="bg-orange-50 border-l-4 border-orange-400 p-4 rounded-r-lg shadow-sm">
                <p className="font-bold text-orange-800 leading-tight text-sm">
                  You don't need these to finish your documents today, this is just for information as it is a good idea to get these ready while we post the documents to you.
                </p>
              </div>
            </div>

            <div className="space-y-6">
              {hasUniversalCredit && (
                <div className="p-6 border-2 border-gray-100 rounded-xl shadow-sm bg-white hover:border-cyan-200 transition-all">
                  <p className="text-lg font-bold text-gray-400 mb-3 uppercase tracking-wide">Universal Credit</p>
                  <p className="text-gray-600 leading-relaxed text-sm font-medium">
                    A copy of your <span className="text-cyan-500 font-bold">Universal Credit Statement</span> for the last assessment period.
                  </p>
                </div>
              )}
              {selectedIncomeTypes.map(id => {
                const detail = evidenceData[id];
                if (!detail) return null;
                return (
                  <div key={id} className="p-6 border-2 border-gray-100 rounded-xl shadow-sm bg-white hover:border-cyan-200 transition-all">
                    <p className="text-lg font-bold text-gray-400 mb-3 uppercase tracking-wide">
                      {detail.title}
                    </p>
                    <p className="text-gray-600 leading-relaxed text-sm font-medium">
                      {detail.desc}
                    </p>
                  </div>
                );
              })}
              {!hasUniversalCredit && selectedIncomeTypes.length === 0 && (
                <div className="p-10 border-2 border-dashed border-gray-200 rounded-xl text-center text-gray-400 italic">No evidence items to display.</div>
              )}
            </div>
          </div>
        )}

        {/* VIEW 7: PAYMENT */}
        {currentView === "payment" && (
          <div className="space-y-10 animate-fadeIn bg-white p-8 rounded-2xl shadow-xl border border-gray-100">
            <div className="space-y-6">
              <div className="border-l-4 border-cyan-400 pl-6 py-2">
                <p className="text-lg font-medium text-gray-600">
                  {finalAmount === 184
                    ? "You have said that You do not qualify for remission (discount) or exemption of the fees."
                    : "You qualify for remission (discount) of the fees."}
                </p>
                <button
                  onClick={() => setCurrentView("exemption-check")}
                  className="text-cyan-500 hover:text-cyan-600 underline font-bold mt-2 transition-colors"
                >
                  Click here to go back and change your selection
                </button>
              </div>

              <div className="flex items-baseline gap-4">
                <p className="text-2xl font-bold text-gray-800">The amount due is</p>
                <p className="text-5xl font-black text-cyan-500">£{finalAmount}</p>
              </div>

              <div className="space-y-4">
                <p className="font-black text-gray-800 text-xl">Please tell us how you would like to pay below.</p>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="bg-gray-50 p-6 rounded-xl border border-gray-200 hover:shadow-md transition-shadow">
                    <p className="font-bold text-[#334a5e] mb-2 uppercase tracking-wide">Cheque</p>
                    <p className="text-sm text-gray-600 leading-relaxed italic">
                      Send a cheque addressed to 'Office of the Public Guardian' with your application writing the name of the donor (<span className="text-cyan-500 font-bold">{donorName}</span>) on the back.
                    </p>
                  </div>
                  <div className="bg-gray-50 p-6 rounded-xl border border-gray-200 hover:shadow-md transition-shadow">
                    <p className="font-bold text-[#334a5e] mb-2 uppercase tracking-wide">Card</p>
                    <p className="text-sm text-gray-600 leading-relaxed italic">
                      Provide a contact phone number below so the Office of the Public Guardian can contact you to take payment.
                    </p>
                  </div>
                </div>
              </div>
            </div>

            <div className="pt-6">
              <p className="text-xl font-black mb-6 text-gray-800">How do you want to pay the registration fees?</p>
              <div className="flex flex-col border-2 border-[#334a5e] rounded-xl overflow-hidden shadow-lg transition-all">
                <button
                  onClick={() => setPaymentMethod("Card")}
                  className={`p-6 text-2xl font-bold transition-all flex items-center justify-center gap-3 ${paymentMethod === "Card" ? "bg-[#334a5e] text-white" : "bg-white text-gray-700 hover:bg-gray-50"}`}
                >
                  {paymentMethod === "Card" && <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>}
                  Card
                </button>
                <button
                  onClick={() => setPaymentMethod("Cheque")}
                  className={`p-6 text-2xl font-bold border-t-2 border-[#334a5e] transition-all flex items-center justify-center gap-3 ${paymentMethod === "Cheque" ? "bg-[#334a5e] text-white" : "bg-white text-gray-700 hover:bg-gray-50"}`}
                >
                  {paymentMethod === "Cheque" && <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>}
                  Cheque
                </button>
              </div>
            </div>

            {paymentMethod === "Card" && (
              <div className="space-y-4 animate-slideDown p-6 bg-cyan-50 rounded-xl border border-cyan-100 shadow-inner">
                <p className="font-bold text-gray-800 text-lg">Contact phone number for payment:</p>
                <TextField
                  fullWidth
                  variant="outlined"
                  value={phoneNumber}
                  onChange={(e) => setPhoneNumber(e.target.value)}
                  placeholder="e.g. 07700 900000"
                  className="bg-white rounded-lg shadow-sm"
                  sx={{
                    '& .MuiOutlinedInput-root': {
                      '&.Mui-focused fieldset': {
                        borderColor: '#06b6d4',
                      },
                    },
                  }}
                />
              </div>
            )}
          </div>
        )}

        {/* NAVIGATION BUTTONS */}
        <div className="flex items-center justify-between mt-16 pb-10">
          <button
            onClick={() => {
              if (currentView === "payment") {
                if (hasBenefits) setCurrentView("evidence-exemption");
                else if (incomeLess12k) {
                  setCurrentView("remission-check");
                  setRemissionStep(2);
                }
                else {
                  setCurrentView("remission-check");
                  setRemissionStep(1);
                }
              }
              else if (currentView === "evidence-exemption") setCurrentView("exemption-check");
              else if (currentView === "remission-check") {
                if (remissionStep === 2) setRemissionStep(1);
                else setCurrentView("exemption-check");
              }
              else if (currentView === "evidence-remission") {
                if (incomeLess12k) {
                  setCurrentView("remission-check");
                  setRemissionStep(2);
                } else {
                  // This branch should ideally not be reached anymore given the forward logic,
                  // but keeping for robustness.
                  setCurrentView("remission-check");
                  setRemissionStep(1);
                }
              }
              else if (currentView === "exemption-check") { /* Step-level back handled by WizardLayout */ }
            }}
            className={`flex items-center gap-2 text-gray-400 font-bold hover:text-gray-600 transition-colors ${currentView === "exemption-check" ? "invisible" : ""}`}
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
              <path fillRule="evenodd" d="M9.707 16.707a1 1 0 01-1.414 0l-6-6a1 1 0 010-1.414l6-6a1 1 0 011.414 1.414L5.414 9H17a1 1 0 110 2H5.414l4.293 4.293a1 1 0 010 1.414z" clipRule="evenodd" />
            </svg>
            <u>Back</u>
          </button>

          <button
            onClick={() => {
              if (currentView === "exemption-check") {
                if (hasBenefits === true) {
                  if (selectedBenefits.length > 0) setCurrentView("evidence-exemption");
                }
                else if (hasBenefits === false) {
                  setCurrentView("remission-check");
                  setRemissionStep(1);
                }
              }
              else if (currentView === "evidence-exemption") setCurrentView("payment");
              else if (currentView === "remission-check") {
                if (remissionStep === 1) {
                  if (incomeLess12k === true) setRemissionStep(2);
                  else setCurrentView("payment");
                } else {
                  setCurrentView("evidence-remission");
                }
              }
              else if (currentView === "evidence-remission") setCurrentView("payment");
              else if (currentView === "payment") {
                if (paymentMethod) handleFinalSave();
              }
            }}
            disabled={
              isSubmitting ||
              (currentView === "exemption-check" && (
                hasBenefits === null || (hasBenefits === true && selectedBenefits.length === 0)
              )) ||
              (currentView === "remission-check" && (
                (remissionStep === 1 && (incomeLess12k === null || hasUniversalCredit === null)) ||
                (remissionStep === 2 && selectedIncomeTypes.length === 0)
              )) ||
              (currentView === "payment" && !paymentMethod) ||
              (currentView === "payment" && paymentMethod === "Card" && !phoneNumber)
            }
            className={`px-10 py-4 rounded text-white font-black shadow-lg transition-all flex items-center justify-center min-w-[240px] ${((currentView === "exemption-check" && hasBenefits === null) ||
              (currentView === "benefit-selection" && selectedBenefits.length === 0) ||
              (currentView === "remission-check" && (
                (remissionStep === 1 && (incomeLess12k === null || hasUniversalCredit === null)) ||
                (remissionStep === 2 && selectedIncomeTypes.length === 0)
              )) ||
              (currentView === "payment" && !paymentMethod) ||
              (currentView === "payment" && paymentMethod === "Card" && !phoneNumber))
              ? "bg-gray-400 cursor-not-allowed"
              : "bg-[#06b6d4] hover:bg-cyan-600 active:scale-95 shadow-cyan-200"
              } `}
          >
            {isSubmitting ? <CircularProgress size={24} color="inherit" /> : (currentView === "payment" ? "Save and finish" : (currentView.startsWith("evidence") ? "Continue" : "Save and continue"))}
          </button>
        </div>
      </div>
    </main>
  );
}
